INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('pago-canon-arrendamiento','Pago del canon de arrendamiento en caso de incumplimiento del inquilino','Si el inquilino no cumple con el pago del canon de arrendamiento en las fechas establecidas en el contrato, SURA paga al arrendador el canon adeudado.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('pago-cuota-administracion','Pago de la cuota de administración que incumpla el inquilino','Pago de la cuota de administración incumplida por el inquilino, siempre y cuando esté incluida en el contrato.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('reembolso-servicios-publicos','Reembolso de servicios públicos por incumplimiento del inquilino','Reembolso del valor de los servicios públicos que el propietario deba asumir por el incumplimiento de pago de los inquilinos. Para cánones inferiores a $4.000.000 cubre hasta el doble; para cánones superiores reembolsa el 1.5% del valor, con tope de $15.000.000 cuando el canon excede $8.000.000. Solo se paga cuando el inquilino abandona el inmueble.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('asistencia-domiciliaria','Asistencia domiciliaria','Servicios de plomería, electricidad, cerrajería, reemplazo de vidrios, seguridad, gastos de traslado por interrupción de viaje y asistencia jurídica telefónica para el cuidado y protección del inmueble.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('danos-a-terceros-responsabilidad-civil-extracontractual','Pago por daños a terceros ocasionados por el inquilino','Pago por los daños a terceros que hayan sido ocasionados por el inquilino de la propiedad.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('danos-y-faltantes-inventario','Daños y faltantes del inventario','Paga los daños y faltantes de los bienes incluidos en el inventario inicial del contrato, siempre que se comprueben al momento de la entrega del inmueble. No cubre daños por deterioro del tiempo (pintura, fisuras, humedades, desprendimiento de techos, entre otros).','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('clausulas-penales-multas-intereses-sanciones','Cláusulas penales, multas, intereses y sanciones económicas','Cláusulas penales, multas, intereses sobre cánones de arrendamiento, cuotas de administración o cualquier otra sanción económica.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('danos-al-inmueble-sin-cobertura-opcional','Daños y faltantes al inmueble arrendado por cualquier causa','Daños y faltantes causados al inmueble arrendado por cualquier causa, salvo que se haya contratado la cobertura opcional de daños y faltantes.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('obligaciones-no-pactadas-por-escrito','Obligaciones no pactadas por escrito o no notificadas a SURA','Cánones de arrendamiento, cuotas de administración, reajustes o servicios públicos domiciliarios que no estén pactados por escrito, no se ajusten a la ley o que no hayan sido notificados a Seguros SURA.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('valor-asegurado-segun-norma','Valor asegurado según la norma base','Cubre hasta el valor asegurado dependiendo de la norma que sirva de base para su expedición.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('pago-danos-incumplimiento-decision-judicial','Pago de daños por incumplimiento de decisión judicial o administrativa','El pago de daños que se generen a la contraparte por el incumplimiento de una decisión judicial o administrativa.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('valor-pretensiones-demandante','Valor de las pretensiones del demandante','El valor mismo de las pretensiones del demandante.','patrimonial') ON CONFLICT(slug) DO NOTHING;
