INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('eximentes-de-responsabilidad','Cualquier otra causa que exima de responsabilidad al asegurado','Cualquier otra circunstancia que exima de responsabilidad al asegurado.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('seriedad-de-la-oferta','Seriedad de la oferta','Asumimos los perjuicios asociados al daño emergente que sufra tu empresa durante el proceso de selección de contratistas o proveedores cuando estos retiren su propuesta sin justa causa, no firmen el contrato tras ser favorecidos, no entreguen el seguro de cumplimiento requerido para la firma, o no modifiquen la garantía de seriedad cuando el proceso se extienda.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('pago-anticipado','Pago anticipado','Pagamos el valor del daño emergente que el contratista cause a tu empresa por la no devolución del pago anticipado entregado, cuando este no haya cumplido con su obligación.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('buen-manejo-correcta-inversion-del-anticipo','Buen manejo, correcta inversión del anticipo','Respaldamos los pagos que le hayas anticipado al contratista en caso de que este no los haya invertido correctamente en la ejecución del contrato.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('cumplimiento','Cumplimiento','Garantizamos el cumplimiento del contrato e indemnizamos los perjuicios que el contratista le cause a tu empresa.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('pago-salarios-prestaciones-sociales-indemnizaciones-laborales','Pago de salarios, prestaciones sociales e indemnizaciones laborales','Respaldamos el pago de salarios, prestaciones sociales e indemnizaciones laborales que el contratista incumpla con el personal que ejecuta el proyecto, siempre y cuando tu negocio sea solidariamente responsable.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('estabilidad-de-la-obra','Estabilidad de la obra','Respondemos por el daño emergente que se produzca debido al deterioro de la obra entregada por el contratista, sea por vicio oculto u otro factor, siempre que la obra haya estado en condiciones normales de uso, haya sido recibida a satisfacción y no pueda cumplir su finalidad.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('calidad-del-bien-o-servicio','Calidad del bien o servicio','Te apoyamos en caso de que los bienes suministrados o el servicio prestado por el contratista o proveedor tengan una calidad deficiente respecto de las especificaciones del contrato y las condiciones de calidad e idoneidad del Estatuto del Consumidor u otras normas técnicas.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('buen-manejo-de-materiales-y-equipos','Buen manejo de materiales y equipos','Si el contratista no te devuelve los materiales y equipos que tu empresa le facilitó para la ejecución del contrato, o los regresa con fallas y averías, te pagaremos el daño emergente que esto le cause a tu empresa.','patrimonial') ON CONFLICT(slug) DO NOTHING;
