INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('responsabilidad-civil-danos-a-terceros','Responsabilidad civil por daños a terceros','Te protege en caso de que tu mascota cause daños materiales, lesiones o incluso la muerte a un tercero. SURA se encarga de los costos de reparación o compensación necesarios.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-veterinarios','Gastos veterinarios','Cubre los gastos en los que incurras debido a enfermedad o accidente de tu mascota. Incluye consultas, tratamientos, hospitalización y medicación necesaria para garantizar la salud de tu mascota.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-exequiales-o-funerarios','Gastos exequiales o funerarios','En caso de que tu mascota fallezca o sea necesario aplicarle la eutanasia, SURA ofrece un auxilio económico para cubrir los gastos funerarios, asegurando que tu mascota tenga un adiós digno.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-por-robo-o-perdida-de-mascota','Gastos por robo o pérdida de mascota','Proporciona un auxilio económico si tu mascota es robada o desaparece, ayudándote a afrontar la situación y buscar soluciones.','patrimonial') ON CONFLICT(slug) DO NOTHING;
