INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('traslado-por-emergencia','Traslado de tu mascota por alguna emergencia','Incluida en Plan Global y Plan Clásico. No incluida en Plan Básico.','asistencia') ON CONFLICT(slug) DO NOTHING;
