INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('urgencia-dental','Urgencia dental para tu mascota','Incluida únicamente en Plan Global. No incluida en Plan Clásico ni Plan Básico.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('refuerzo-esquema-hexavalente-anual','Refuerzo de esquema hexavalente anual','Incluida únicamente en Plan Global. No incluida en Plan Clásico ni Plan Básico.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('vehiculo-de-reemplazo','Movilidad tras un siniestro','Si no puedes usar tu auto después de un siniestro, te damos alternativas para que puedas movilizarte.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('grua-y-reparacion-en-talleres-aliados','Reparación en talleres aliados','Si tu auto necesita reparación después de un accidente, lo llevamos a talleres aliados y nos encargamos de que quede en buenas manos.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('reparacion-danos-menores-vidrios-llantas-accesorios','Daños menores: vidrios, llantas y accesorios','Si tienes un daño menor en tu auto, como un choque leve o un vidrio roto, te ayudamos con la reparación o cambio de piezas con vidrios, llantas o accesorios.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('soat','SOAT','Este seguro no incluye SOAT, lo complementa.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('accidentes-personales','Accidentes personales','Si tú o una persona a la que le hayas prestado la bicicleta o la patineta llegan a fallecer o sufren alguna invalidez o desmembración luego de un accidente, pagaremos una indemnización dependiendo de las consecuencias del accidente.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('perdidas-totales-por-dano-o-hurto','Pérdidas totales por daño o hurto','Asumimos la pérdida total de tu patineta o bicicleta cuando sufra daños materiales como consecuencia de accidentes, actos de terrorismo, eventos de la naturaleza (terremotos, incendios, inundaciones, etc.) y acciones malintencionadas por parte de terceros. También aplica si desaparece de manera permanente como consecuencia de un robo.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('renta-diaria-por-hospitalizacion','Renta diaria por hospitalización','Te ofrecemos una renta diaria por el valor asegurado a partir del tercer día de hospitalización y hasta por treinta días, por cada año de vigencia de este seguro.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('asistencia','Asistencia','Si sufres un accidente, te brindamos asesoría jurídica telefónica o en el sitio y acompañamiento ante el Tránsito o Centro de Conciliación. Asumimos los gastos por traslado médico hasta el centro hospitalario más cercano, hasta el límite de la cobertura, y ofrecemos transporte para ti y tu bicicleta o patineta hasta tu domicilio habitual en caso de varada o accidente.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('asistencia-varada-grua','Si te varaste o se te pinchó una llanta','Nos haremos cargo del traslado de la moto hasta el lugar donde la reparen.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('taller-movil-bateria-gasolina','Si se descarga la batería o te quedas sin gasolina','Nuestro taller móvil va hasta donde estés para ayudarte. Puedes usarlo ilimitadamente.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('asistencia-juridica-accidente','Si tienes un accidente y necesitas un abogado','Te pondremos en contacto con un profesional de SURA de forma virtual o presencial.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-transporte-perdida-total','Gastos de transporte por pérdida total','Gastos de transporte, hasta por 30 días, en caso de pérdida total de la moto.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('perdida-total','Pérdida total','Cobertura de pérdida total de la moto por daños o hurto.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('perdida-parcial','Pérdida parcial','Cobertura de pérdida parcial de la moto por daños o hurto.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('servicio-de-grua','Servicio de grúa','Servicio de grúa en casos de varada o accidente.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('consultas-mecanicas-pre-viaje','Consultas mecánicas a expertos antes de un viaje','Consultas gratuitas mecánicas a expertos antes de un viaje (en Motos SURA Bogotá, Cali y Medellín).','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('carro-taller','Carro taller para imprevistos','Carro taller para imprevistos como pinchadas de llanta o daño de batería.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('asesoria-juridica-telefonica','Asesoría jurídica vía telefónica o en el sitio del accidente','Asesoría jurídica vía telefónica o en el sitio del accidente.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('trayectoria-alineacion-frenado-suspension','Trayectoria de alineación, frenado y suspensión delantera y trasera','Prueba de pista en la que el vehículo se pone en movimiento para evaluar características como trayectoria de alineación, frenado y suspensión delantera y trasera.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('aspectos-estructurales-autos','Aspectos estructurales','Con el automóvil en unos elevadores, los expertos revisan la originalidad y estado de la carrocería, chasis y pintura, así como posibles fugas de líquidos como agua, aceite o refrigerante.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('prueba-caja-y-motor','Prueba de caja y motor','Permite conocer el estado real del motor del vehículo que vas a comprar; se adquiere por un costo adicional.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('computador-autos','Computador','El controlador de las funciones electrónicas del vehículo se conecta a un escáner para identificar las fallas que pueda tener. Si son borrables, se eliminan; en caso contrario, se recomienda la remisión a un concesionario.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('llantas-autos','Llantas','Se miden el aire y la profundidad de las llantas para determinar su vida útil o, de ser pertinente, recomendar su cambio.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('aire-acondicionado','Aire acondicionado','Se chequea su funcionamiento general, es decir, que sus niveles de potencia, temperatura y rejillas trabajen correctamente.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('pintura-autos','Pintura','Mediante la observación de su textura y acabados, con un medidor de espesores o un micrómetro se establece si la pintura es original o el vehículo fue repintado y, en ese caso, si el proceso fue adecuado.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('vidrios-y-retrovisores','Vidrios y retrovisores','En los laterales se observa el funcionamiento de los mandos (manuales o eléctricos) y que el cristal no esté roto o rayado. El vidrio trasero y panorámico se inspeccionan con especial atención, pues su mal estado puede ser causa de sanciones de tránsito.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('suspension-y-frenos-autos','Suspensión y frenos','En una pista se comprueban los niveles de eficacia. Un sensor electrónico reporta si un amortiguador está húmedo o golpeado, o si las pastillas de frenos deben cambiarse o están bajas de líquido. También se examinan los discos y pastas.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('luces-autos','Luces','Se verifica que prendan y apaguen correctamente y que funcionen el cambio de luces bajas, altas, exploradoras, direccionales, de reversa y traseras que anuncian el frenado.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('antecedentes-multas-e-infracciones-autos','Antecedentes, multas e infracciones','Con el apoyo de Ajustev, aliado de SURA en asesorías jurídicas y técnicas, se consulta y cruza información de las secretarías de movilidad para revisar antecedentes, multas e infracciones, tarjeta de propiedad y seriales del motor y el chasis, comprobando que no estén alterados o regrabados y, en caso de estarlo, que esté autorizado por los entes de control.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('aspectos-estructurales-motos','Aspectos estructurales (moto)','Inspección visual del chasis, basculante y carenado. Aplican condiciones.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('computador-motos','Computador (moto)','Mediante un escáner se realiza un diagnóstico computarizado que evalúa las posibles fallas de la moto en las unidades electrónicas. Aplican condiciones según el tipo de vehículo. Servicio adicional que solo se presta en Medellín y se debe solicitar en el peritaje.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('llantas-motos','Llantas (moto)','Se verifica la profundidad, desgaste, estado y caducidad de las llantas para determinar su vida útil o, si es pertinente, su cambio.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('pintura-motos','Pintura (moto)','Mediante una detallada observación se evalúa el acabado de la pintura y, con el medidor de espesor, la calidad de la reparación del vehículo (si aplica).','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('retrovisores-motos','Retrovisores (moto)','Chequeo de su funcionamiento, adhesión al manubrio y que sean graduables, además de que no estén rotos o rayados.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('suspension-y-frenos-motos','Suspensión y frenos (moto)','Se revisa que en la estructura de la suspensión no haya fugas ni golpes que afecten el funcionamiento de la moto.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('luces-motos','Luces (moto)','Se verifica que prendan y apaguen correctamente y que funcionen el cambio de luces bajas, altas, direccionales y traseras que anuncian el frenado.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('antecedentes-multas-e-infracciones-motos','Antecedentes, multas e infracciones (moto)','Se revisan las bases de datos del RUNT, Fasecolda y la Policía Nacional para chequear si el vehículo tiene embargos, auditorías o registro de hurtos. Se valida la originalidad de la tarjeta de propiedad y los números de identificación del vehículo, comprobando que no estén alterados o regrabados y, en caso de estarlo, que esté autorizado por los entes de control.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('componentes-internos-caja-y-motor-moto','Componentes internos de la caja de velocidad y del motor (moto)','El peritaje de moto no incluye la revisión del estado de los componentes internos de la caja de velocidad y del motor (ni su compresión).','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-medicos-y-de-transporte','Gastos médicos y gastos de transporte','La reclamación la hará la entidad hospitalaria o prestadora del servicio de ambulancia.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('incapacidad-permanente','Incapacidad permanente','La reclamación la hará quien fue víctima del accidente de tránsito. A partir del 1 de febrero de 2024 el pago se hará únicamente a favor del beneficiario legal.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('muerte-y-gastos-funerarios','Muerte','La reclamación la harán los beneficiarios de la ley.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('incapacidad-temporal','Incapacidad temporal','El SOAT no paga las incapacidades temporales (de duración por tiempo determinado, días o meses). Estas deben ser tramitadas por la EPS o ARL.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('errores-omisiones-dictamenes-periciales','Errores y omisiones en dictámenes periciales','SURA pagará los perjuicios ocasionados en caso de que cometas un error u omisión al actuar como perito en un proceso judicial.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('responsabilidad-civil-tratamiento-datos-personales','Responsabilidad civil por fallas en el tratamiento de datos sensibles o personales','Podrás hacer uso de esta cobertura cuando la información de tus pacientes sea revelada por una falla en el tratamiento de sus datos, y esto les cause algún daño.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-defensa-reclamaciones-tribunal-etica-medica','Gastos de defensa por reclamaciones civiles o de Tribunal de Ética Médica','SURA cubrirá los gastos de defensa si un tercero hace una reclamación por un evento que cubra este seguro. También te acompañará en caso que inicien un proceso disciplinario contra ti ante el Tribunal de Ética Médica.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('responsabilidad-civil-uso-equipos-especiales','Responsabilidad civil por el uso de equipos especiales','SURA te acompañará en caso de una reclamación por daños ocasionados a tus pacientes cuando utilices equipos como: radiografía con fines de diagnóstico, rayos X para terapéutica, tomografía por ordenador (escáner), radiación por isótopos para terapéutica, generación de rayos láser y medicina nuclear, siempre que dichos equipos no estén sujetos a un seguro obligatorio de responsabilidad civil por daños nucleares previsto por la ley.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('ejercicio-sin-habilitacion-legal','Ejercicio de la profesión sin habilitación legal','No cubre cuando ejerzas tu profesión sin estar legalmente habilitado.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('fin-diferente-diagnostico-tratamiento','Profesión con fin diferente al diagnóstico o tratamiento','No cubre si tu profesión tiene un fin diferente al diagnóstico o tratamiento.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('cirugias-plasticas-tratamientos-esteticos','Cirugías plásticas o tratamientos estéticos','No cubre cuando se trate de cirugías plásticas o tratamientos estéticos. Esta exclusión no aplica para cirugías reconstructivas posteriores a un accidente, y correctivas de anomalías congénitas.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('resultado-de-intervencion','Reclamación por resultado de una intervención','No cubre cuando la reclamación se dé por el resultado de una intervención.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('danos-bajo-influencia-alcohol-sustancias','Daños bajo influencia de alcohol o sustancias alucinógenas','No cubre si causas daños estando bajo la influencia de bebidas alcohólicas o sustancias alucinógenas.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('violacion-secreto-profesional','Violación del secreto profesional','No cubre cuando causes un perjuicio al violar un secreto profesional.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('procedimientos-equipos-en-fase-experimental','Medicamentos, equipos o procedimientos en fase experimental','No cubre cuando uses medicamentos, máquinas, equipos o procedimientos en fase experimental, o no cumplas las reglas de la técnica para utilizarlos.','responsabilidad') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('plan-de-recompensas','Plan de recompensas','Programa que recompensa el cumplimiento de metas; los comportamientos saludables permiten acumular puntos.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('centro-de-experiencias-para-el-bienestar','Centro de experiencias para el bienestar','Lugar interactivo para descubrir qué hábitos modificar y cuáles fortalecer, y proyectar el estado de salud al que se desea llegar.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('tu-bienestar-al-dia','Tu bienestar al día','Acompañamiento en la gestión de la salud para estar siempre un paso adelante.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('programas-de-bienestar','Programas de bienestar',NULL,'asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('atencion-virtual-en-salud','Atención virtual en salud','Como cliente del Seguro de Salud se puede evaluar el estado de salud desde cualquier lugar.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('plan-nuevamente','Plan nuevamente','Serie de servicios para que el cliente y sus seres queridos tengan una vida activa, saludable y segura.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('cancer-y-leucemia','Cáncer y leucemia','Estas enfermedades se caracterizan por el crecimiento descontrolado de células malignas y la invasión de tejidos.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('infarto-del-miocardio','Infarto del miocardio','El infarto del miocardio se produce por el bloqueo de una o más arterias coronarias, lo que causa la muerte de una porción del corazón. El diagnóstico se establece a partir de síntomas como dolor de pecho, cambios en el electrocardiograma y elevación de enzimas cardíacas.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('enfermedad-cerebrovascular','Enfermedad cerebrovascular','Cubrimos la enfermedad cerebrovascular causada por una hemorragia o un infarto en el tejido cerebral, que puede resultar en déficit neurológico.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('insuficiencia-renal-cronica','Insuficiencia renal crónica','La insuficiencia debe ser permanente e irreversible en ambos riñones y que como consecuencia requieras hemodiálisis, diálisis peritoneal o trasplante de riñón.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('paralisis-de-miembros','Parálisis de miembros superiores o inferiores','Se refiere a la pérdida completa e irreversible de la función de los miembros superiores o inferiores, causada por enfermedad o accidente.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('perdida-de-miembros','Pérdida de miembros superiores o inferiores','Se refiere a la amputación quirúrgica o traumática de miembros superiores o inferiores, como resultado de una enfermedad o accidente.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('perdida-total-de-la-audicion','Pérdida total de la audición','Se refiere a la pérdida permanente e irreversible de la audición en ambos oídos, como resultado de un accidente o una enfermedad.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('perdida-total-de-la-vision','Pérdida total de la visión','Se refiere a la pérdida total, permanente e incorregible de la visión en ambos ojos.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('esclerosis-multiple','Esclerosis múltiple','La esclerosis múltiple es una enfermedad inflamatoria crónica caracterizada por la formación de lesiones desmielinizantes en el sistema nervioso central.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('estado-de-coma','Estado de coma','Se refiere a un estado de inconsciencia total que debe durar al menos 96 horas. El coma no puede ser resultado del consumo de alcohol o sustancias tóxicas.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('revascularizacion-arterial-coronaria','Revascularización arterial coronaria','Es una cirugía de corazón abierto que se realiza para corregir el estrechamiento o la obstrucción de una o más arterias coronarias. Esta intervención requiere la colocación de al menos dos injertos o puentes para restaurar el flujo sanguíneo adecuado al corazón.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('trasplante-de-organo-mayor','Trasplante de órgano mayor','Te respaldamos en caso de que recibas un trasplante de órgano mayor, que incluye el restablecimiento de conexiones vasculares, arteriales y venosas. Los órganos trasplantados que cubrimos son: hígado, corazón, médula ósea, páncreas, pulmón e intestino delgado.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('traumatismo-mayor-de-cabeza','Traumatismo mayor de cabeza','Se refiere a un trastorno de la función cerebral debido a un impacto o lesión grave en la cabeza. No se cubre este evento si fue causado por un accidente en moto.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('reemplazo-total-de-valvula-del-corazon','Reemplazo total de válvula del corazón','Respaldamos la primera ocurrencia de reemplazo de una o más válvulas del corazón mediante cirugía abierta.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('tumor-cerebral-benigno','Tumor cerebral benigno','Se refiere al crecimiento de células tumorales benignas en el encéfalo, que requieren tratamiento mediante cirugía o radioterapia y pueden causar secuelas neurológicas permanentes.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('esclerosis-lateral-amiotrofica-ela','Esclerosis lateral amiotrófica (ELA)','Es una enfermedad neurológica progresiva que afecta las células nerviosas motoras en la corteza cerebral y la médula espinal. Esta condición causa atrofia muscular, debilidad y eventualmente insuficiencia respiratoria.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('enfermedad-de-alzheimer','Enfermedad de Alzheimer','Cubrimos el diagnóstico definitivo de la enfermedad de alzheimer antes de los 70 años de edad.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('enfermedad-de-parkinson','Enfermedad de Parkinson','Cubrimos el diagnóstico inequívoco de la enfermedad primaria idiopática de parkinson antes de los 70 años de edad.','salud') ON CONFLICT(slug) DO NOTHING;
