INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('repatriacion','Repatriación por enfermedad, accidente o fallecimiento','Repatriación por enfermedad, accidente o fallecimiento, siempre que haya contacto previo con Asistencia en Viajes SURA, aprobación médica y saldo disponible en la cobertura. Aplica únicamente para pólizas familiares.','asistencia') ON CONFLICT(slug) DO NOTHING;
