INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('urgencias-odontologicas-domicilio-plan','Atencion de urgencias odontologicas a domicilio','Disponible 24 horas. Sujeto a las zonas de cobertura del prestador. Aplica copago. Adicionales: 1 limpieza dental por vigencia sin costo, y 25% de descuento en tratamientos odontologicos o aliados. No incluida en Plan Esencial.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('robo-documentos','Si te roban los documentos durante el viaje','Te reembolsamos hasta 200 USD.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('perdida-o-demora-equipaje','Si tu equipaje se pierde o llega tarde a tu destino','Te pagamos hasta 500 USD para que puedas comprar lo que necesites.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('cancelacion-vuelo','Si la aerolínea cancela tu viaje','Te pagamos 300 USD para cubrir los gastos.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('emergencia-medica','Si tienes una emergencia médica','Te pagamos hasta 75.000 USD para cubrir gastos por medicamentos ambulatorios u otras complicaciones médicas.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-medicos-por-accidente-y-enfermedad','Seguro de Salud (gastos médicos)','Cobertura principal de gastos médicos que brinda atención integral en caso de un imprevisto de salud durante el viaje, sin que tengas que asumir pagos o trámites en el lugar donde te encuentres.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('equipaje','Equipaje','Si pierdes tu equipaje o este se retrasa, te indemnizamos con el monto contratado. En caso de retraso, la indemnización será inmediata.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('acompanante','Acompañante','Cubrimos el traslado y hospedaje de un acompañante durante tu enfermedad o accidente, si así lo requieres.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('cancelacion-de-vuelo-o-viaje','Cancelación de vuelo o viaje','En caso de que tu aerolínea cancele el vuelo, te reconocemos el valor contratado. Incluye la cancelación voluntaria por causa laboral, médica o de otro tipo, siempre que sea debidamente justificada.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-por-robo-de-documentos','Gastos por robo de documentos','Si te roban los documentos durante el viaje, te indemnizamos por el valor de los gastos que hayas asumido para reponerlos.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('extension-de-viaje-hospedaje-y-desplazamiento','Hospedaje y desplazamiento por extensión del viaje','Asumimos el hospedaje y desplazamiento tuyo y de un acompañante si debes extender el viaje por alguna situación médica.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('repatriacion-por-fallecimiento','Repatriación por fallecimiento','Asumimos el costo de una repatriación en caso de fallecimiento.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('orientacion-medica-telefonica','Orientación médica telefónica','Recibe atención médica por medio de llamada telefónica desde donde estés para ser atendido por un experto y, de acuerdo con tu estado de salud, te orientamos de la mejor manera.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('polizas-de-salud','Pólizas de salud','Pólizas de salud de SURA. Conoce más descargando los términos y condiciones.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('sedes-salud-sura','Sedes Salud SURA','Sedes exclusivas para la atención en salud de los asegurados.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('directorio-medico','Directorio Médico','Acceso al directorio médico para encontrar los servicios que necesitas.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('cobertura-medica-en-el-exterior','Cobertura en el exterior','Atención médica de emergencia o urgencia en el extranjero.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('plataforma-bienestar-longevo','Longevo','Plataforma de Bienestar de SURA para transformar tus hábitos.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('servicios-en-linea','Servicios en línea','Servicios en línea de Salud SURA. Conoce más descargando los términos y condiciones.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('programas-especiales-de-salud','Programas especiales de salud','Acompañamiento de acuerdo con el momento de vida en el que te encuentres.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('toma-de-muestras-a-domicilio','Toma de muestras a domicilio','Servicio de toma de muestras a domicilio.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('invalidez-desmembracion-inutilizacion-por-accidente','Invalidez, desmembracion o inutilizacion por accidente','En caso de un accidente que ocasione invalidez total o perdida funcional de ciertos organos o partes del cuerpo, entregamos una indemnizacion equivalente al porcentaje de invalidez que establezca Seguros SURA.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('invalidez-desmembracion-inutilizacion-por-enfermedad','Invalidez, desmembracion o inutilizacion (cobertura opcional)','Te indemnizamos en caso de adquirir alguna enfermedad que te cause invalidez, inutilizacion o alguna desmembracion en tu cuerpo.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-de-curacion','Gastos de curacion','Te reembolsamos el dinero que gastes como consecuencia de un accidente: hospitalizacion, medicamentos, elementos de curacion, derechos de sala de cirugia, honorarios medicos u odontologicos, anestesia, examenes de laboratorio, transfusiones de sangre, rayos X, servicios de enfermeria, ambulancias, gastos de fisioterapia, entre otros.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('renta-diaria-por-accidente','Renta diaria por accidente','Si sufres un accidente que te ocasione una incapacidad medica, te entregamos un respaldo economico diario por el valor que contrates, dependiendo del diagnostico medico.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('dolo-culpa-grave-acto-voluntario','Siniestro por dolo, culpa grave o acto voluntario','No cubre cuando en el siniestro haya habido dolo, culpa grave o se haya ocasionado por un acto voluntario.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('intoxicaciones-lumbalgias-espasmos-hernias','Intoxicaciones, lumbalgias, espasmos musculares y hernias','No cubre intoxicaciones, lumbalgias, espasmos musculares y hernias de cualquier clase.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('enfermedades-congenitas-preexistencias','Enfermedades congenitas, defectos fisicos y preexistencias','No cubre enfermedades congenitas o lesiones, defectos fisicos y enfermedades originadas o adquiridas antes de la contratacion de la cobertura, salvo que no las conocieras. Aplica asi declares que padeces la enfermedad antes de contratar la cobertura.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('mala-fe-en-la-reclamacion','Mala fe en la reclamacion','No cubre cuando haya mala fe del asegurado o beneficiario en la reclamacion o en la comprobacion del derecho al pago del siniestro.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('reclamacion-fuera-de-prescripcion','Reclamacion fuera de los terminos de prescripcion','No cubre cuando la reclamacion se realice por fuera de los terminos de prescripcion.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('exclusiones-especificas-por-cobertura','Exclusiones definidas para cada cobertura','No cubre cuando apliquen las exclusiones definidas para cada cobertura.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('incapacidad-total-y-permanente','Incapacidad total y permanente por enfermedad o accidente','Si por un accidente o una enfermedad pierdes el 50 % o más de tu capacidad laboral, asumimos la deuda que tengas con la entidad financiera a la fecha del siniestro. Si queda parte del valor asegurado, se te entrega.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('auxilio-de-exequias','Auxilio de exequias','Si llegas a fallecer, pagamos a tus beneficiarios siete millones de pesos para destinarlos a los gastos funerarios.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('fondo-de-ahorro','Fondo de ahorro','Además de la prima de tu seguro, tienes la posibilidad de hacer un pago adicional para ahorrar y obtener rendimiento. Este dinero lo puedes retirar cuando desees o usarlo para pagar las primas del Plan Crédito Protegido que tengas en mora.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('deportes-riesgosos','Práctica de deportes riesgosos','La práctica de deportes riesgosos como parapentismo, montañismo, paracaidismo, escalada de montañas, rafting, downhill, esquí en hielo, entre otros que no hayas declarado al contratar este seguro o durante su vigencia.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('exclusion-auxilio-exequias-enfermedad-carencia','Auxilio de exequias por enfermedad en periodo de carencia','Para el auxilio de exequias: no habrá indemnización cuando la muerte sea por una enfermedad que adquiriste dentro de los sesenta días siguientes al momento en que contrataste la cobertura.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('costos-de-matricula','Costos de matrícula','Con pagos periódicos de cuotas o incluso un solo pago, construyes el capital para cubrir tus gastos educativos o los de tus seres queridos. Tú acumulas el respaldo económico y luego SURA lo desembolsa para pagar la matrícula. El desembolso no pierde valor con el tiempo (aumenta en enero de cada año según el IPC del DANE) y el riesgo financiero es asumido por la Compañía.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('gastos-de-manutencion','Gastos de manutención','Podrás programar pagos mensuales para cubrir gastos de manutención durante el periodo de estudio, tales como alimentación, vivienda o transporte.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('plan-vida-escolar','Plan Vida Escolar','Si llegas a fallecer o a sufrir una invalidez total o permanente antes de comenzar los desembolsos de la cobertura principal (renta educativa), garantizamos que la persona para la que hayas tomado el seguro reciba una cantidad de dinero mensual que podrá utilizar para asumir los gastos escolares de formación preescolar, primaria o secundaria.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('plan-vida-complemento','Plan Vida Complemento','Si aún no has finalizado el plan de pagos de la cobertura principal (renta educativa) y falleces o sufres una invalidez total o permanente, este plan terminará de pagar por ti, garantizando que tus seres queridos tengan acceso a la educación.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('muerte-por-suicidio-primer-ano','Muerte por suicidio dentro de los doce meses siguientes','Muerte por suicidio, estando o no el tomador del Seguro de Educación en uso de sus facultades mentales, dentro de los doce meses siguientes a la contratación de esta cobertura o al aumento de los valores asegurados de la misma. Aplica a las coberturas Vida Escolar y Vida Complemento.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('deportes-extremos-conduccion-artefactos-aereos','Conducción de vehículos o artefactos aéreos en deportes extremos','Conducción de vehículos o artefactos aéreos como parapentes, ultralivianos, paracaídas y planeadores usados en deportes extremos, entre otros. Aplica a la cobertura de incapacidad total y permanente de Vida Escolar y Vida Complemento.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('actos-de-guerra-y-conmocion-social','Actos de guerra y conmoción social','Actos de guerra interior o exterior, revolución, rebelión, sedición, asonada o actos violentos motivados por conmoción social o por aplicación de la ley marcial. Aplica a la cobertura de incapacidad total y permanente de Vida Escolar y Vida Complemento.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('servicio-militar-naval-aereo-policia','Prestación del servicio militar, naval, aéreo o de policía','Prestación del servicio militar, naval, aéreo o de policía. Aplica a la cobertura de incapacidad total y permanente de Vida Escolar y Vida Complemento.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('fision-fusion-nuclear-radioactividad','Fisión o fusión nuclear o radioactividad','Fisión o fusión nuclear o radioactividad. Aplica a la cobertura de incapacidad total y permanente de Vida Escolar y Vida Complemento.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('enfermedades-preexistentes-congenitas','Enfermedades congénitas o preexistentes','Enfermedades congénitas o lesiones, defectos físicos y enfermedades originadas, ocurridas o adquiridas antes de la contratación de la cobertura, incluso si el tomador del Seguro de Educación no las conocía. Aplica a la cobertura de incapacidad total y permanente de Vida Escolar y Vida Complemento.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('intento-suicidio-invalidez-intencional','Intento de suicidio o invalidez provocada intencionalmente','Intento de suicidio o invalidez provocados intencionalmente. Aplica a la cobertura de incapacidad total y permanente de Vida Escolar y Vida Complemento.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('respaldo-economico-fallecimiento','Respaldo económico por fallecimiento','Entrega a tus beneficiarios (o a quien haya asumido los gastos funerarios) un respaldo económico en caso de que fallezcas.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('reembolso-excedente-valor-asegurado','Reembolso del excedente del valor asegurado','Reembolsa a tus beneficiarios el dinero del valor asegurado que sobra de los gastos exequiales.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('cobertura-homicidio-accidente-suicidio','Cobertura ante homicidio, accidente y suicidio','Cobertura ante homicidio, accidente y suicidio desde el día en que compras el seguro.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('inclusion-personas-adicionales-grupo-familiar','Inclusión de personas adicionales en el grupo familiar','Posibilidad de incluir personas adicionales dentro del grupo familiar.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('orientacion-telefonica-exequial','Orientación telefónica exequial','Orientación telefónica para acompañar y asesorar a los familiares cuando el asegurado fallezca.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('reembolso-gastos-repatriacion','Reembolso de gastos de repatriación','Reembolso de gastos de repatriación en caso de muerte durante viaje en el exterior.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('dinero-adicional-muerte-accidental','Dinero adicional por muerte accidental','Da a tus beneficiarios un dinero adicional en caso de muerte accidental.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('dinero-adicional-invalidez-desmembracion-accidente','Dinero adicional por invalidez y desmembración por accidente','Da un dinero adicional en caso de invalidez y desmembración por accidente.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('renta-diaria-hospitalizacion-accidente','Renta diaria por hospitalización por accidente','Pago por cada día que estés hospitalizado como producto de un accidente.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('renta-mensual-pension','Renta mensual de pensión','Ingreso mensual que recibirás en el futuro para complementar o anticipar tu pensión; no pierde valor en el tiempo y aumenta cada enero según el IPC de los últimos 12 meses decretado por el DANE.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('capital-de-respaldo','Capital de respaldo','Capital que garantiza calidad de vida a futuro para el asegurado y sus seres queridos, asumiendo SURA el riesgo financiero.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('abonos-adicionales','Abonos adicionales','Posibilidad de hacer dos tipos de abonos adicionales, programados desde la contratación o en el momento en que se desee aportar durante el período de pago de primas.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('modificacion-periodo-estudio','Modificación del período de estudio','Permite aplazar o adelantar la fecha de inicio del período de estudio por máximo un año, ampliar o reducir el período de estudio, y modificar la periodicidad en la que se recibe el ingreso adquirido durante ese período.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('sin-exclusiones','Sin exclusiones','Este seguro no tiene exclusiones.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('fallecimiento','Respaldo económico por fallecimiento','Proporcionar respaldo económico a tus beneficiarios en caso de fallecimiento.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('saldo-deuda-credito','Cobertura de saldo de deuda','Cubrir el monto de la deuda que no hayas alcanzado a pagar a tu beneficiario oneroso en caso de muerte o invalidez.','patrimonial') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('enfermedades-graves','Enfermedades graves','Respaldo económico en caso de que seas diagnosticado con enfermedades graves.','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('auxilio-exequias','Auxilio de exequias','Le damos a tus familiares un auxilio de exequias.','asistencia') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('ahorro','Posibilidad de ahorro','Posibilidad de ahorro.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('devolucion-de-dinero','Devolución de dinero','Devolución de dinero si decides cancelar el seguro en algún momento.','otros') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('aseguramiento-de-por-vida-pago-unico','Aseguramiento de por vida mediante pago único','Posibilidad de asegurarte de por vida mediante un único pago.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('invalidez-y-desmembramiento-por-accidente','Invalidez y desmembramiento por accidente','Darte dinero en caso de invalidez y desmembramiento por accidente.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('invalidez-y-desmembramiento-por-enfermedad','Invalidez y desmembramiento por enfermedad','Entregar dinero en caso de invalidez y desmembramiento por enfermedad.','vida') ON CONFLICT(slug) DO NOTHING;
INSERT INTO cobertura(slug,nombre,descripcion,categoria) VALUES('reembolso-gastos-medicos-por-accidente','Reembolso de gastos médicos por accidente','Te reembolsamos los gastos médicos derivados de accidentes (ideal si no tienes EPS).','salud') ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('colectivos','Seguros Colectivos',(SELECT id FROM ramo WHERE slug='empresas-colectivos'),'empresas','juridica','Una solución para grandes empresas que buscan asegurar su patrimonio y el bienestar de sus empleados. Para este canal, SURA cuenta con compañías especializadas en atender la protección integral de la empresa y sus empleados, y genera alianzas con empresas de servicios públicos, cajas de compensación, entidades financieras y corredores autorizados para ofrecer soluciones de seguros ajustadas a las necesidades de cada organización.','Soluciones de seguros colectivos para grandes empresas que protegen su patrimonio y el bienestar de sus empleados.','https://www.sura.co/seguros/colectivos',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-agro-bovino-bufalino','Seguro Bovino y Bufalino',(SELECT id FROM ramo WHERE slug='empresas-agro'),'empresas','ambas','Protegemos tus bovinos ante eventos naturales, enfermedades y otras coberturas descritas en el clausulado general de la póliza.','Seguro para ganaderos que protege bovinos y bufalinos ante muerte o pérdida productiva por eventos naturales y enfermedades.','https://www.sura.co/seguros/empresas/agro/bovino/bufalino',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-agro-cosecha','Seguro Agrícola de Cosecha',(SELECT id FROM ramo WHERE slug='empresas-agro'),'empresas','ambas','Protegemos sus cultivos contra eventos naturales como excesos de lluvias, sequías, vientos fuertes y más. Podrás ser parte de un programa de competitividad que integra los seguros que tengas con la gestión de riesgos por medio de Empresas SURA, eligiendo las coberturas que se ajusten a tu necesidad.','Seguro que protege los cultivos de agricultores de todos los tamaños frente a eventos naturales que afectan la cosecha.','https://www.sura.co/seguros/empresas/agro/cosecha',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-agro-planta','Seguro Agrícola de Planta',(SELECT id FROM ramo WHERE slug='empresas-agro'),'empresas','ambas','Protegemos sus cultivos contra eventos naturales como excesos de lluvias, sequías, vientos fuertes y más. Podrás ser parte de un programa de competitividad que integra los seguros que tengas con la gestión de riesgos por medio de Empresas SURA.','Seguro que protege los cultivos de agricultores de todos los tamaños contra eventos de la naturaleza que causen la muerte de las plantas.','https://www.sura.co/seguros/empresas/agro/planta',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-colectivos-autos','Seguro Colectivo de Autos',(SELECT id FROM ramo WHERE slug='empresas-colectivos'),'empresas','juridica','Protegemos los vehículos de uso familiar, incluyendo eléctricos e híbridos, de tus colaboradores con una póliza colectiva que ofrece tarifas preferenciales y la posibilidad de financiarla sin intereses, así cuidas su bienestar y fortaleces su vínculo con tu empresa.','Póliza colectiva de autos para colaboradores de empresas, con tarifas preferenciales, financiación sin intereses y varios planes; requiere mínimo 7 vehículos.','https://www.sura.co/seguros/empresas/colectivos/autos','https://www.suraenlinea.com/movilidad/sura/seguro-de-carro',FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-colectivos-pension','Seguro de Pensión',(SELECT id FROM ramo WHERE slug='empresas-colectivos'),'empresas','juridica','Gracias al Seguro de Pensión que ofrecemos en SURA, tus empleados podrán adquirir una cultura de ahorro y asegurar los ingresos que complementarán su pensión en unos años. Con esta alternativa, tendrán la posibilidad de garantizar un capital de respaldo para que ellos y sus seres queridos disfruten de calidad de vida en el futuro. El empleado define por cuánto tiempo quiere pagar y cuál es la periodicidad más cómoda: una suma única o a través de cuotas mensuales de mínimo $100.000 o sus equivalentes trimestrales, semestrales o anuales. El ingreso mensual que recibirá no pierde valor en el tiempo y es garantizado; el riesgo financiero lo asume SURA.','Seguro pensional colectivo para que las empresas ayuden a sus empleados a construir un capital que complemente su pensión con ingresos garantizados.','https://www.sura.co/seguros/empresas/colectivos/pension',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-colectivos-vida-accidentes-personales','Seguro de Accidentes Personales Colectivo',(SELECT id FROM ramo WHERE slug='empresas-colectivos'),'empresas','juridica','Seguro colectivo dirigido a personas que hacen parte de un colectivo laboral y que, por la naturaleza de su trabajo, están expuestas a riesgos accidentales. Cubre muerte accidental e invalidez o pérdida por un accidente.','Seguro colectivo de accidentes personales que protege a trabajadores expuestos a riesgos accidentales con coberturas de muerte e invalidez.','https://www.sura.co/seguros/empresas/colectivos/vida/accidentes/personales',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-construccion-equipo-electronico','Seguro de Equipo Electrónico',(SELECT id FROM ramo WHERE slug='empresas-construccion'),'empresas','ambas','El Seguro de Equipo Electrónico de SURA está diseñado para proteger tus equipos electrónicos contra los riesgos que pueden causar daños o pérdidas. Un seguro es especialmente útil para empresas y profesionales que dependen de tecnología avanzada y equipos especializados en su operativa diaria. Respalda casos como errores humanos y situaciones que perjudican el adecuado funcionamiento de los elementos electrónicos de tu organización.','Protege los equipos electrónicos de tu empresa contra daños, errores humanos y eventos accidentales.','https://www.sura.co/seguros/empresas/construccion/equipo/electronico',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-construccion-maquinaria-equipo-contratistas','Seguro de Maquinaria y Equipo de contratistas',(SELECT id FROM ramo WHERE slug='empresas-construccion'),'empresas','ambas','Protegemos tu maquinaria ante daños y pérdidas, cuidando tu patrimonio y que puedas brindar confianza y tranquilidad a tus clientes.','Seguro que protege la maquinaria y equipo de contratistas frente a daños, eventos de la naturaleza y hurto, cuidando el patrimonio de empresas y personas naturales.','https://www.sura.co/seguros/empresas/construccion/maquinaria/equipo/contratistas',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-construccion-montaje','Seguro de Montaje',(SELECT id FROM ramo WHERE slug='empresas-construccion'),'empresas','ambas','Protegemos tus proyectos de montaje ante posibles riesgos, para que avances con confianza y brindes seguridad a tus clientes. Está dirigido a empresas de todos los tamaños y personas naturales que vayan a iniciar un montaje, ya sea de maquinaria de gran tamaño, plantas o estructuras metálicas de todo tipo.','Seguro que protege proyectos de montaje de maquinaria, plantas y estructuras metálicas ante daños materiales y otros riesgos.','https://www.sura.co/seguros/empresas/construccion/montaje',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-construccion-obras-civiles-terminadas','Seguro de Obras Civiles Terminadas',(SELECT id FROM ramo WHERE slug='empresas-construccion'),'empresas','juridica','Aseguramos la operación de tus obras de infraestructura, para que sigan funcionando en el menor tiempo posible ante eventos inesperados. Protege empresas públicas o privadas, concesiones y asociaciones público-privadas encargadas de la operación de una obra de infraestructura frente a daños materiales, eventos de la naturaleza, hurto y actos malintencionados de terceros.','Seguro para empresas que protege la operación de obras civiles de infraestructura terminadas ante eventos inesperados.','https://www.sura.co/seguros/empresas/construccion/obras/civiles/terminadas',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-construccion-seguro-construccion','Seguro de Construcción',(SELECT id FROM ramo WHERE slug='empresas-construccion'),'empresas','ambas','Aseguramos tus obras de construcción ante imprevistos, para que avances con tranquilidad y generes confianza en tus clientes.','Seguro que protege obras de construcción de empresas y personas naturales ante daños, hurtos y eventos de la naturaleza.','https://www.sura.co/seguros/empresas/construccion/seguro/construccion',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-corporativos-pymes-multirriesgo-copropiedades','Seguro Multirriesgo Copropiedades',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','El Seguro Multirriesgo Copropiedades de SURA protege las copropiedades comerciales o industriales, así como sus áreas comunes, respaldando daños o pérdidas materiales ante riesgos como incendios, rayos, explosiones, deslizamientos, terremotos, erupciones volcánicas y otros eventos. Según la Ley 675 de 2001, toda propiedad horizontal está obligada a adquirir un seguro que cubra los bienes comunes contra estos riesgos.','Seguro que protege los bienes y áreas comunes de copropiedades comerciales o industriales ante incendios, terremotos y otros riesgos.','https://www.sura.co/seguros/empresas/corporativos/pymes/multirriesgo/copropiedades',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-cumplimiento-arrendamiento','Seguro de Arrendamiento',(SELECT id FROM ramo WHERE slug='empresas-cumplimiento'),'empresas','juridica','Seguro de Cumplimiento para contratos de arrendamiento que garantiza al arrendador los ingresos generados por sus locales, bodegas u otros espacios. La cobertura principal responde al incumplimiento de pagos de arriendo, servicios públicos y administración, con protecciones opcionales como daños y faltantes de inventario y asistencia domiciliaria. Está disponible de manera individual (por cada propiedad arrendada) y colectiva (a través de agencias inmobiliarias).','Garantiza los ingresos por arrendamiento de la empresa cuando el inquilino incumple el pago del canon, la administración y los servicios públicos.','https://www.sura.co/seguros/empresas/cumplimiento/arrendamiento',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-cumplimiento-caucion-judicial','Seguro de Caución Judicial',(SELECT id FROM ramo WHERE slug='empresas-cumplimiento'),'empresas','ambas','Respaldamos las obligaciones que surjan de procesos jurídicos o administrativos para ayudarte a proteger tu patrimonio. Está dirigido a empresas de todos los tamaños y personas naturales que estén involucradas en un proceso jurídico o administrativo.','Seguro que respalda las obligaciones derivadas de procesos jurídicos o administrativos para proteger tu patrimonio.','https://www.sura.co/seguros/empresas/cumplimiento/caucion/judicial',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-cumplimiento-contratistas-proveedores','Cumplimiento para proveedores y contratistas',(SELECT id FROM ramo WHERE slug='empresas-cumplimiento'),'empresas','ambas','Respaldamos el incumplimiento por parte de tus proveedores o contratistas frente a los compromisos establecidos con tu empresa. Cubre desde la seriedad de la oferta hasta la estabilidad de la obra, calidad del bien o servicio y el buen manejo del anticipo, materiales y equipos.','Seguro que respalda a tu empresa ante el incumplimiento de proveedores y contratistas en sus compromisos contractuales.','https://www.sura.co/seguros/empresas/cumplimiento/contratistas/proveedores',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-cumplimiento-disposiciones-legales','Seguro de Cumplimiento de Disposiciones Legales',(SELECT id FROM ramo WHERE slug='empresas-cumplimiento'),'empresas','ambas','Protegemos el patrimonio de una entidad estatal frente a los perjuicios que puede generarle el incumplimiento de las obligaciones que tenga tu empresa, contempladas en leyes, decretos, ordenanzas, acuerdos, resoluciones, entre otras normas.','Seguro que protege a una entidad estatal frente a los perjuicios por el incumplimiento de obligaciones legales por parte de tu empresa.','https://www.sura.co/seguros/empresas/cumplimiento/disposiciones/legales',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-cumplimiento-entidades-estatales','Seguro de Cumplimiento a Favor de Entidades Estatales',(SELECT id FROM ramo WHERE slug='empresas-cumplimiento'),'empresas','ambas','Respaldamos el incumplimiento que pueda llegar a tener tu empresa frente a los compromisos adquiridos con una entidad estatal.','Garantía de cumplimiento para empresas y personas naturales que contratan con entidades estatales, respaldando el incumplimiento de sus obligaciones contractuales.','https://www.sura.co/seguros/empresas/cumplimiento/entidades/estatales',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-cumplimiento-grandes-beneficiarios','Seguro de Cumplimiento para Grandes Beneficiarios',(SELECT id FROM ramo WHERE slug='empresas-cumplimiento'),'empresas','ambas','Respaldamos el incumplimiento que puedan tener tus proveedores y contratistas frente a los compromisos establecidos con tu empresa.','Respalda a tu empresa frente al incumplimiento de proveedores y contratistas en los compromisos contractuales.','https://www.sura.co/seguros/empresas/cumplimiento/grandes/beneficiarios',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-cumplimiento-particulares','Seguro de Cumplimiento a Favor de Particulares',(SELECT id FROM ramo WHERE slug='empresas-cumplimiento'),'empresas','ambas','Respaldamos el incumplimiento que pueda llegar a tener tu empresa frente a los compromisos adquiridos con personas jurídicas o naturales.','Seguro que respalda el incumplimiento de tu empresa frente a contratos con particulares (personas naturales o jurídicas).','https://www.sura.co/seguros/empresas/cumplimiento/particulares',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-cumplimiento-servicios-publicos','Seguro de Cumplimiento a Favor de Empresas de Servicios Públicos',(SELECT id FROM ramo WHERE slug='empresas-cumplimiento'),'empresas','ambas','Respaldamos el incumplimiento que tenga tu empresa frente a los compromisos adquiridos con una empresa de servicios públicos. El tomador son las empresas de todos los tamaños y personas naturales que sean contratadas formalmente para prestar un servicio, producir algo, construir una obra, entre otros. La empresa de servicios públicos será la asegurada.','Seguro que respalda el cumplimiento de los compromisos de tu empresa frente a empresas de servicios públicos.','https://www.sura.co/seguros/empresas/cumplimiento/servicios/publicos',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-energia-eficiencia-energetica','Seguro de Cumplimiento de Eficiencia Energética y Generación de Energía',(SELECT id FROM ramo WHERE slug='empresas-energia'),'empresas','ambas','Garantizamos el cumplimiento de la promesa de ahorro o generación de energía de tus proyectos de eficiencia energética o generación de energía, asegurando que tu inversión esté protegida.','Seguro que garantiza el cumplimiento de la promesa de ahorro o generación de energía en proyectos de eficiencia energética o generación de energía.','https://www.sura.co/seguros/empresas/energia/eficiencia/energetica','https://www.segurossura.com.co/documentos/informacion-proyecto-energia.xlsx',FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-politica-suscripcion-asg','Suscripción con criterios ASG',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','En SURA entendemos que los criterios Ambientales, Sociales y de Gobernanza (ASG) tienen impacto en empresas de cualquier tamaño y sector. Su análisis es crucial para una gestión integral del riesgo y para contribuir a su competitividad en el tiempo. La suscripción ASG busca ampliar la mirada a criterios no financieros que pueden impactar lo financiero y que influyen en la sostenibilidad de las empresas en el corto, mediano y largo plazo.','Política de suscripción de SURA que integra criterios Ambientales, Sociales y de Gobernanza (ASG) en el aseguramiento de empresas.','https://www.sura.co/seguros/empresas/politica/suscripcion/asg',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-ambiental','Responsabilidad Civil Ambiental',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','Protegemos tu patrimonio ante daños ambientales accidentales que puedan afectar a terceros y poner en riesgo la continuidad de tu empresa. Está dirigido a empresas de todos los tamaños cuyas actividades económicas puedan generar una contaminación accidental, ya sea súbita o gradual, que afecte directamente su propio predio o el de terceros.','Seguro que protege el patrimonio de empresas ante daños ambientales accidentales que afecten a terceros.','https://www.sura.co/seguros/empresas/responsabilidad/civil/ambiental',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-clinicas-hospitales','Seguro de Responsabilidad Civil para Clínicas y Hospitales',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','Protegemos tu entidad ante perjuicios causados por actos u omisiones en la prestación de servicios de salud. Respalda a clínicas y hospitales legalmente habilitados frente a reclamaciones por daños materiales, muerte o lesiones personales derivadas de servicios médicos, quirúrgicos, dentales, de enfermería, farmacéuticos o de laboratorio.','Responsabilidad civil para clínicas y hospitales ante daños o perjuicios derivados de la prestación de servicios de salud.','https://www.sura.co/seguros/empresas/responsabilidad/civil/clinicas/hospitales',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-danos-terceros','Seguro de Responsabilidad Civil por Daños a Terceros',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','En el ejercicio de su actividad económica, tu empresa está expuesta a algunos riesgos que pueden ocasionar daños a terceros. Este seguro cubre los gastos de indemnización generados por daños materiales o lesiones personales que puedan ocasionarse en el ejercicio de la actividad empresarial, incluyendo gastos médicos y de defensa, protegiendo el patrimonio de la empresa con una solución integral y a la medida de sus necesidades.','Protege el patrimonio de tu empresa ante daños materiales o personales causados a terceros en el ejercicio de tu actividad económica.','https://www.sura.co/seguros/empresas/responsabilidad/civil/danos/terceros',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-drones','Responsabilidad Civil para Drones',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','ambas','Protegemos tu patrimonio ante daños a terceros causados durante la operación de drones en tu actividad económica. Dirigido a empresas de todos los tamaños y a personas naturales que usen drones en el desarrollo de su actividad económica cumpliendo con la reglamentación de la Aeronáutica Civil.','Seguro que protege tu patrimonio ante daños a terceros causados por la operación de drones en tu actividad económica.','https://www.sura.co/seguros/empresas/responsabilidad/civil/drones',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-familiar','Responsabilidad Civil Familiar',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','natural','Protegemos tu patrimonio y tranquilidad ante daños involuntarios que tú o tu familia puedan causar a terceros en la vida cotidiana. Cubre al asegurado principal y su familia en primer grado de consanguinidad que residan en el mismo predio, así como a las mascotas del grupo familiar (perros y gatos). Las empresas pueden incluir la póliza colectiva de Responsabilidad Civil Familiar dentro de su plan de beneficios para colaboradores y obtener descuento.','Seguro que protege tu patrimonio ante daños involuntarios que tú, tu familia o tus mascotas causen a terceros en la vida cotidiana.','https://www.sura.co/seguros/empresas/responsabilidad/civil/familiar',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-fraude-empleado','Seguro de Fraude de Empleados',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','Protegemos tu empresa ante pérdidas económicas causadas por fraudes o actos deshonestos cometidos por tus colaboradores.','Cubre las pérdidas económicas de tu empresa por fraudes o actos deshonestos de tus empleados.','https://www.sura.co/seguros/empresas/responsabilidad/civil/fraude/empleado',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-parqueaderos','Seguro de Responsabilidad Civil para Parqueaderos',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','ambas','Protegemos tu patrimonio por daños a terceros o vehículos durante la operación de tu parqueadero, generando confianza en tus clientes. Cuenta con una amplia cobertura, sin límites en los perjuicios por daños a bienes, lucro cesante, daños morales o afectaciones a la salud de las personas.','Seguro que protege el patrimonio de parqueaderos públicos y privados por daños a terceros y vehículos durante su operación.','https://www.sura.co/seguros/empresas/responsabilidad/civil/parqueaderos',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-responsabilidad-empleador','Seguro de Responsabilidad del Empleador',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','ambas','Protegemos tu patrimonio, en caso de que algún colaborador sufra un accidente por el cual debas asumir responsabilidad e indemnizarlo. Contarás con una amplia cobertura, sin límites en los perjuicios por daños a bienes, lucro cesante, daños morales o afectaciones a la salud de las personas.','Protege el patrimonio de la empresa frente a indemnizaciones por accidentes laborales de colaboradores propios o de contratistas.','https://www.sura.co/seguros/empresas/responsabilidad/civil/responsabilidad/empleador',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil-talleres','Responsabilidad Civil para Talleres',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','Protegemos tu patrimonio ante daños a terceros o vehículos durante la operación de tu taller, generando confianza en tus clientes. Está dirigido a talleres y concesionarios de carros o motos que cuenten con los debidos permisos y licencias requeridos para operar.','Seguro de responsabilidad civil que protege a talleres y concesionarios de carros o motos ante daños a terceros o vehículos durante su operación.','https://www.sura.co/seguros/empresas/responsabilidad/civil/talleres',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-responsabilidad-civil','Pólizas de Responsabilidad Civil',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','En el ejercicio de su actividad económica, las empresas están expuestas a riesgos que pueden ocasionar daños a terceros. Seguros SURA ofrece un portafolio de pólizas de Responsabilidad Civil para empresas que protege el patrimonio de la organización ante reclamaciones por daños materiales, lesiones personales y perjuicios causados a terceros en distintos sectores y actividades.','Portafolio de pólizas de Responsabilidad Civil para empresas que protege el patrimonio ante daños causados a terceros.','https://www.sura.co/seguros/empresas/responsabilidad/civil',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-sectores-transporte','Sector Transporte',(SELECT id FROM ramo WHERE slug='empresas-sectores'),'empresas','juridica','Soluciones de Seguros SURA para el sector transporte que combinan seguros y servicios de asesoria para gestionar los riesgos y asegurar la operacion logistica y de movilidad de la empresa, acompanando toda la cadena de abastecimiento desde el origen hasta el destino.','Seguros y asesoria gratuita para proteger la operacion logistica y el transporte de mercancias de las empresas.','https://www.sura.co/seguros/empresas/sectores/transporte',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-sura','Seguro de Equipo Electrónico',(SELECT id FROM ramo WHERE slug='empresas-otros'),'empresas','juridica','El Seguro de Equipo Electrónico de SURA está diseñado para proteger tus equipos electrónicos contra los riesgos que pueden causar daños o pérdidas. Es especialmente útil para empresas y profesionales que dependen de tecnología avanzada y equipos especializados en su operativa diaria, respaldando casos como errores humanos y situaciones que perjudican el adecuado funcionamiento de los elementos electrónicos de tu organización.','Protección para los equipos electrónicos de tu empresa frente a daños, errores humanos y pérdidas.','https://www.sura.co/seguros/empresas/sura',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-transporte-cadena-abastecimiento','Soluciones de Riesgo Logístico y Marítimos',(SELECT id FROM ramo WHERE slug='empresas-transporte'),'empresas','juridica','Protegemos tu cadena de abastecimiento para que enfrentes con confianza los riesgos que amenazan tu continuidad operativa. Dirigido a empresas generadoras de carga dedicadas a la fabricación, distribución mayorista, minorista, exportación e importación, con una de las coberturas más amplias del mercado para proteger la mercancía durante todo el trayecto a nivel nacional e internacional.','Seguro de transporte de mercancías que protege la cadena de abastecimiento de empresas generadoras de carga a nivel nacional e internacional.','https://www.sura.co/seguros/empresas/transporte/cadena/abastecimiento',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-transporte-carga-proyectos','Seguro para Carga de Proyecto',(SELECT id FROM ramo WHERE slug='empresas-transporte'),'empresas','juridica','Protegemos el transporte de equipos para tus proyectos de ingeniería, cubriendo daños, pérdidas de bienes y pérdida anticipada de utilidad. Esta solución está orientada a grandes proyectos de ingeniería, como plantas de generación de energía, de tratamiento de aguas, refinerías, obras mineras, ferroviarias, industriales y similares.','Seguro que protege el transporte de equipos y bienes críticos para grandes proyectos de ingeniería, incluyendo la pérdida anticipada de utilidad.','https://www.sura.co/seguros/empresas/transporte/carga/proyectos',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-transporte-mercancias-automatico','Seguro de Transporte de Mercancías Automático',(SELECT id FROM ramo WHERE slug='empresas-transporte'),'empresas','juridica','Protegemos tus productos y materias primas durante su transporte, cubriendo pérdidas o daños que puedan afectar tu operación. Está dirigido a empresas dedicadas a la producción, distribución, importación o exportación de bienes, con un valor asegurado por documento de transporte y no por vehículo transportador.','Seguro empresarial que protege mercancías y materias primas durante su transporte ante pérdidas o daños.','https://www.sura.co/seguros/empresas/transporte/mercancias/automatico',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-transporte-mercancias-especifico','Seguro de Transporte de Mercancías Específico',(SELECT id FROM ramo WHERE slug='empresas-transporte'),'empresas','juridica','Protegemos la mercancía de tu envío específico frente a riesgos durante su transporte, para que llegue seguro sin importar el modo o destino. Está dirigido a empresas que realicen envíos ocasionales de productos terminados o materias primas, cubriendo operaciones urbanas, nacionales, importaciones y exportaciones en los diferentes modos de transporte (aéreo, marítimo, terrestre, férreo y fluvial).','Seguro para empresas que protege la mercancía de un envío específico u ocasional frente a riesgos durante su transporte en cualquier modo o destino.','https://www.sura.co/seguros/empresas/transporte/mercancias/especifico',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('empresas-transporte-terrestres-carga','Transporte para Transportador Terrestre',(SELECT id FROM ramo WHERE slug='empresas-transporte'),'empresas','juridica','Protegemos mercancías de tus clientes, frente a las pérdidas y daños en su transporte terrestre, que estén bajo la responsabilidad de tu empresa.','Seguro empresarial que cubre pérdidas y daños de las mercancías transportadas por vía terrestre bajo responsabilidad de la empresa transportadora.','https://www.sura.co/seguros/empresas/transporte/terrestres/carga',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-hogar-arrendamiento-tradicional','Seguro de Arrendamiento',(SELECT id FROM ramo WHERE slug='personas-hogar-y-vivienda'),'personas','ambas','En SURA cuidamos tus ingresos. Sabemos lo importante que es recibir el pago mensual de tus inmuebles, por eso contamos con Oficinas Especializadas en Arrendamiento en todo el país. Si tu inquilino no cumple, tenemos el plan ideal para acompañarte en todo el proceso, con respaldo legal y para que siempre recibas tu renta, con tranquilidad y respaldo.','Garantiza tus ingresos como arrendador con respaldo legal y asistencia para tu inmueble si tu inquilino incumple el pago del canon.','https://www.sura.co/seguros/personas/hogar/arrendamiento/tradicional','https://www.sura.co/documents/d/seguros/cotizador-arrendamiento',FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-hogar-arrendamiento','Seguro de Arrendamiento',(SELECT id FROM ramo WHERE slug='personas-hogar-y-vivienda'),'personas','ambas','En SURA, sabemos lo importante que es para ti recibir el pago mensual de tus inquilinos. Por eso, nuestro Seguro de Arrendamiento está diseñado para brindarte bienestar y tranquilidad en caso de que tu inquilino no cumpla con sus obligaciones. Si alguna vez esto sucede, ¡no te preocupes! Te respaldamos y garantizamos que siempre recibas tus ingresos.','Seguro que garantiza el pago del arriendo y las obligaciones del inquilino en caso de incumplimiento.','https://www.sura.co/seguros/personas/hogar/arrendamiento','https://www.sura.co/seguros/personas/hogar/arrendamiento/digital',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-hogar-hogar','Seguro de Hogares SURA',(SELECT id FROM ramo WHERE slug='personas-hogar-y-vivienda'),'personas','natural','¡En SURA entendimos que un hogar es mucho más que una casa!, es donde construyes sueños y creas recuerdos. Por eso nos dedicamos a protegerlo de la forma en que tú lo necesitas. Ya sea que lo utilices como espacio para tu negocio, como el refugio de tus seres queridos o como una inversión para el futuro. Recuerda que estamos aquí para garantizar su seguridad y tranquilidad.','Seguro de hogar que protege tu vivienda, contenidos, electrodomésticos y elementos personales ante incendio, desastres naturales, robo y daños, con asistencias domésticas y asesoría jurídica.','https://www.sura.co/seguros/personas/hogar/hogar',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-hogar-mascotas','Seguro de Mascotas SURA',(SELECT id FROM ramo WHERE slug='personas-hogar-y-vivienda'),'personas','natural','Sabemos que tus mascotas son una parte fundamental de tu Familia. Con esta solución SURA te respalda protegiendo tu patrimonio, en caso de que este se vea afectado por cualquier evento relacionado con tus perros o gatos, y te acompaña satisfaciendo tus necesidades y las de tus mascotas, a través de la prestación de diferentes servicios, para que puedas cuidarlos, atenderlos y consentirlos como se lo merecen.','Seguro para perros y gatos que protege tu patrimonio y ofrece gastos veterinarios, responsabilidad civil y servicios de cuidado para tu mascota.','https://www.sura.co/seguros/personas/hogar/mascotas',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-hogar','Seguro de Hogar SURA',(SELECT id FROM ramo WHERE slug='personas-hogar-y-vivienda'),'personas','natural','El Seguro de Hogar SURA es una inversión en tu tranquilidad y bienestar. Con nosotros puedes disfrutar de tu espacio con la certeza de que estás protegido ante cualquier eventualidad. Asegurar tu vivienda con SURA es una inversión en tu tranquilidad y bienestar. No dejes que imprevistos arruinen el hogar que tanto te ha costado construir.','Seguro de hogar SURA que protege tu vivienda ante imprevistos y eventualidades.','https://www.sura.co/seguros/personas/hogar','https://www.segurossura.com.co/paginas/hogar/otros-planes.aspx',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-movilidad-autos-digital','Seguro automóvil digital',(SELECT id FROM ramo WHERE slug='personas-movilidad'),'personas','natural','Asegura tu carro 100% digital. Complementa el SOAT y conduce con la tranquilidad de estar protegido, con planes que se adaptan a tu estilo de vida. Luego de comprar el seguro tendrás 48 horas para realizar la inspección, con la opción de hacerla de manera virtual.','Seguro de carro 100% digital que complementa el SOAT con planes Clásico, Básico y Global.','https://www.sura.co/seguros/personas/movilidad/autos/digital','https://ecomm.sura.co/seguros/movilidad/autos/cotizador',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-movilidad-bicicletas-patinetas','Seguro de Bicis y Patinetas',(SELECT id FROM ramo WHERE slug='personas-movilidad'),'personas','natural','Si tienes una bici o una patineta como medio de transporte y disfrutas de la libertad y agilidad de desplazarte en ella, este plan es para ti. En SURA te acompañamos si tu bici o patineta tiene una pérdida total por robo o daños, y contarás con respaldo si sufres un incidente o te ves involucrado en un accidente contra un objeto o persona. Además, te ayudamos a cuidar de tu vehículo en el Centro de Servicios SURA o de forma virtual con la asesoría de expertos en postura, acondicionamiento físico y consultoría mecánica.','Seguro para bicicletas y patinetas que cubre daños a terceros, accidentes personales, pérdidas totales por daño o hurto y asistencia.','https://www.sura.co/seguros/personas/movilidad/bicicletas/patinetas',NULL,TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-movilidad-motos-digital','Seguro de motos digital',(SELECT id FROM ramo WHERE slug='personas-movilidad'),'personas','natural','Compra tu Seguro de Motos 100% digital, fácil y rápido. Protege tu inversión con planes flexibles. Este seguro no incluye SOAT, lo complementa.','Seguro de moto 100% digital con planes flexibles que protege tu inversión y complementa el SOAT.','https://www.sura.co/seguros/personas/movilidad/motos/digital','https://ecomm.sura.co/seguros/movilidad/motos/cotizador',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-movilidad-motos','Seguro de Motos',(SELECT id FROM ramo WHERE slug='personas-movilidad'),'personas','natural','Viaja con tranquilidad en tu moto porque estarás protegido con SURA. Con SURA puedes asegurar tu moto de alto cilindraje (mayor que 250 cc) o de bajo cilindraje (igual o menor que 250 cc). Además, cuentas con tres revisiones preventivas al año sin costo y asesorías ilimitadas con un mecánico experto, beneficios a los que podrás acceder en el Centro de Servicios Motos SURA o de manera virtual. Al adquirir tu seguro, también tendrás un peritaje gratuito.','Seguro para motos de alto y bajo cilindraje con responsabilidad civil, pérdida total/parcial, asistencia en vía y servicios mecánicos.','https://www.sura.co/seguros/personas/movilidad/motos','https://www.sura.co/seguros/personas/movilidad/motos/digital',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-movilidad-peritaje','Peritaje SURA para autos y motos',(SELECT id FROM ramo WHERE slug='personas-movilidad'),'personas','natural','El peritaje es un proceso realizado por expertos responsables de una detallada revisión técnica de cada uno de los elementos de tu vehículo, con el objetivo de verificar el adecuado funcionamiento y estado de sus sistemas eléctrico, mecánico y estructural, así como del grado de originalidad en sus componentes. Por lo general, se realiza cuando vendes o adquieres un vehículo usado.','Revisión técnica experta de autos y motos usados en los Centros de Servicios SURA; no requiere tener seguro SURA.','https://www.sura.co/seguros/personas/movilidad/peritaje',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-movilidad-soat-reclamaciones','SOAT SURA - Reclamaciones',(SELECT id FROM ramo WHERE slug='personas-movilidad'),'personas','natural','Página de canales y proceso de reclamación del SOAT SURA. Permite conocer los requisitos de cada amparo (gastos médicos y de transporte, incapacidad permanente y muerte) y realizar la reclamación de manera digital de forma rápida y sin complicaciones.','Canales y proceso para reclamar el SOAT SURA por gastos médicos, incapacidad permanente o muerte.','https://www.sura.co/seguros/personas/movilidad/soat/reclamaciones','https://www.suraenlinea.com/soat/sura/seguro-obligatorio',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-movilidad','Seguros de Movilidad',(SELECT id FROM ramo WHERE slug='personas-movilidad'),'personas','natural','En SURA te acompañamos a moverte de forma segura, por eso creamos diferentes opciones para que elijas el plan que más se acomoda a tu estilo de vida.','Opciones de seguros de movilidad para que te muevas seguro: carro, moto, bicicleta, patineta, SOAT y más.','https://www.sura.co/seguros/personas/movilidad',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-responsabilidad-civil-profesionales-salud','Seguro de Responsabilidad Civil para Profesionales de la Salud',(SELECT id FROM ramo WHERE slug='personas-otros'),'personas','natural','Al trabajar como profesional de la salud, es tu responsabilidad preservar la vida, la salud, las buenas condiciones físicas o mentales, y la integridad corporal de tus pacientes. Si por algún motivo vulneras alguno de estos derechos, tu paciente o las personas afectadas pueden reclamar una indemnización. En SURA creamos el Seguro de Responsabilidad Civil para Profesionales de la Salud, con el cual buscamos proteger tu patrimonio y acompañarte en este tipo de situaciones. Así podrás ejercer tu profesión con mayor tranquilidad.','Protege el patrimonio de los profesionales de la salud ante reclamaciones por errores u omisiones cometidos en la prestación de su servicio.','https://www.sura.co/seguros/personas/responsabilidad/civil/profesionales/salud',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-como-cuidarte','Cómo cuidarte - Servicios para tu bienestar (Seguro de Salud SURA)',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Página de servicios de bienestar para clientes del Seguro de Salud de SURA. Reúne información y servicios para tener un estilo de vida saludable y cuidar la salud, incluyendo plan de recompensas, centro de experiencias para el bienestar, atención virtual en salud y programas de bienestar.','Servicios de bienestar y acompañamiento en salud para clientes del Seguro de Salud SURA.','https://www.sura.co/seguros/personas/salud/como/cuidarte',NULL,TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-enfermedades-graves','Seguro de Enfermedades Graves SURA',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Con este seguro consolidas el capital necesario para mantener tu calidad de vida en caso de sufrir una enfermedad grave como cáncer, alzheimer, parkinson, entre otras cubiertas. Si eres diagnosticado con una enfermedad de alto costo cubierta, SURA te entrega el valor asegurado para que puedas acceder al tratamiento y tu familia y tú conserven su calidad de vida. Puedes adquirir el respaldo por el valor que elijas y asegurar también a tu grupo familiar (pareja, padres e hijos) para obtener un descuento.','Seguro que entrega un capital al ser diagnosticado con una enfermedad grave de alto costo, protegiéndote a ti y a tu grupo familiar.','https://www.sura.co/seguros/personas/salud/enfermedades/graves',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-mascotas-digital','Seguro de Salud para Mascotas SURA',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Porque tu mascota es parte de tu familia, dale el cuidado que merece con un Seguro de Salud para Mascotas Digital, rápido y sin complicaciones. Plan de salud para perros y gatos con la mejor red veterinaria, con tres planes que se adaptan a tu estilo de vida: desde lo básico hasta lo ultra completo.','Seguro de salud digital para perros y gatos con tres planes (Esencial, Clásico y Global) y red veterinaria avalada SURA.','https://www.sura.co/seguros/personas/salud/mascotas/digital','https://surapet.com.co/alianza/cdd',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-plan-salud-modular','Plan de Salud Modular',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Una forma flexible de proteger tu salud y la de tu familia, combinando coberturas esenciales con modulos adicionales que eliges segun tus necesidades, tu momento de vida y tu presupuesto. Un plan de salud flexible con coberturas que se adaptan a tu momento actual.','Plan de salud flexible que combina coberturas basicas esenciales con modulos opcionales que eliges segun tu etapa de vida y presupuesto.','https://www.sura.co/seguros/personas/salud/plan/salud/modular','https://www.sura.co/seguros/personas/salud/plan-salud-modular#cotiza',FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-poliza-clasica','Póliza de Salud Clásica',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Con la Póliza de Salud Clásica garantizamos el bienestar de las personas, con una cobertura integral y accesible dentro del país, contamos con una amplia red de especialistas e instituciones, así como sedes exclusivas. Permite acceder a coberturas hospitalarias y ambulatorias, solicitar el servicio de emergencias o urgencias domiciliarias, programar citas con especialistas y acceder al Programa de Bienestar y la plataforma Longevo.','Seguro de salud con cobertura hospitalaria y ambulatoria dentro de Colombia, red de especialistas e instituciones y atención médica domiciliaria, para residentes menores de 70 años afiliados a EPS contributiva.','https://www.sura.co/seguros/personas/salud/poliza/clasica',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-poliza-evoluciona','Póliza de Salud Evoluciona',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Con la Póliza de Salud Evoluciona, brindamos atención integral y servicios de calidad. Cuenta con una amplia cobertura dentro del país a través de una red direccionada de especialistas e instituciones, con sedes exclusivas a nivel nacional, además de múltiples canales para una atención eficiente. Esta póliza incluye atención médica a domicilio y consultas ilimitadas con copago, respondiendo tanto a necesidades cotidianas como eventos inesperados.','Plan integral de salud con coberturas hospitalarias y ambulatorias, atención médica a domicilio y consultas ilimitadas con copago a través de una red nacional de prestadores.','https://www.sura.co/seguros/personas/salud/poliza/evoluciona',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-poliza-global','Plan Salud Global SURA',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','El Plan Salud Global de SURA es una opcion ideal para viajeros frecuentes. La Poliza de Salud Global cuenta con la mayor cobertura dentro y fuera del pais, atencion integral y acceso a servicios medicos de calidad, incluyendo tratamientos medicos programados en el exterior y asistencia en viajes.','Seguro de salud con cobertura integral en Colombia y en el extranjero, ideal para viajeros frecuentes, con atencion de emergencias y tratamientos programados en el exterior.','https://www.sura.co/seguros/personas/salud/poliza/global',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-poliza','Póliza de Salud SURA',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Con un Seguro de Salud SURA permaneces tranquilo porque sabes que tienes acceso ilimitado a servicios que no solo complementan tu Plan Obligatorio, sino que además te permiten disfrutar de atenciones exclusivas como consultar directamente a un médico especialista o realizar exámenes de imagenología o radiología, sin necesidad de esperar una autorización por parte del médico general.','Seguro de salud complementario al POS con tres planes (Global, Clásica y Evoluciona) que dan acceso a hospitalización, consulta especializada, tratamientos y asistencia.','https://www.sura.co/seguros/personas/salud/poliza',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-renta-diaria','Seguro Plan Renta Diaria',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','El Seguro Plan Renta Diaria de SURA te paga una indemnizacion diaria en caso de hospitalizacion, cirugia ambulatoria o parto, brindando un respaldo economico adicional al POS o a un Plan Complementario de Salud. Funciona de forma sencilla: aseguras un valor diario (entre $50.000 y $200.000) y, al recibir el alta, te entregamos la indemnizacion correspondiente a los dias hospitalizado para que cuides tus finanzas personales por los ingresos que dejas de percibir mientras estas en recuperacion.','Seguro que paga una indemnizacion diaria por hospitalizacion, cirugia ambulatoria o parto como respaldo economico durante la recuperacion.','https://www.sura.co/seguros/personas/salud/renta/diaria',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-salud-para-dos','Salud para Dos',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Salud para Dos es un seguro de salud que puedes compartir con la persona que tengas registrada en tu plan. Permite compartir coberturas de acceso como atencion virtual, emergencias odontologicas a domicilio, especialistas y ayudas diagnosticas. Aplica para independientes, PYMES y regimenes especiales como magisterio y fuerzas armadas, sin copagos.','Seguro de salud sin copagos que puedes compartir con una persona registrada en tu plan, con planes Estandar y Plus.','https://www.sura.co/seguros/personas/salud/salud/para/dos','https://wa.link/7m5njn',FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-salud-para-todos','Salud para Todos',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Salud para Todos ofrece acceso y coberturas integrales para el cuidado de la salud de nuestros asegurados. Puedes acceder a coberturas basicas y de uso frecuente, asegurando acceso y oportunidad ante eventos de salud no deseados. Con Salud para Todos aseguramos tu bienestar con un plan que se adapta a tus necesidades.','Seguro de salud complementario a la EPS con acceso directo a especialistas, atencion medica a domicilio 24 horas y habitacion individual en hospitalizacion.','https://www.sura.co/seguros/personas/salud/salud/para/todos',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-viajes-digital','Seguro de Viaje Internacional SURA - eSIM 2026',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Viaja protegido con SURA y recibe una eSIM de hasta 10GB para estar siempre conectado. Seguro de viaje internacional 100% digital que te acompaña ante emergencias médicas, pérdida o demora de equipaje, robo de documentos y cancelación de vuelos.','Seguro de viaje internacional 100% digital con eSIM de hasta 10GB y coberturas de salud, equipaje y cancelación.','https://www.sura.co/seguros/personas/salud/viajes/digital','https://ecomm.sura.co/seguros/salud/viajes/cotizador',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud-viajes','Seguro de Viaje',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','El Seguro de Viaje de SURA te acompaña si durante tu viaje tienes un accidente o una enfermedad, coordinando los servicios médicos que requieras. Funciona en todo el mundo y te cubre en casos de emergencia justificada, con asistencia 24/7, cobertura global, respaldo de SURA y pago inmediato de las coberturas. Te paga el valor asegurado si se pierde o demora tu equipaje, te roban tus documentos o cancelas tu viaje.','Seguro de viaje nacional e internacional con gastos médicos, asistencia 24/7 y cobertura global, ideal para viajeros.','https://www.sura.co/seguros/personas/salud/viajes','https://www.sura.co/seguros/personas/salud/viajes/digital',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-salud','Salud SURA',(SELECT id FROM ramo WHERE slug='personas-salud'),'personas','natural','Cuanto más sabemos de ti, mejor podemos protegerte. Por eso, te ofrecemos una variedad de programas y servicios diseñados para cuidarte a ti y a tus seres queridos. Salud SURA reúne pólizas de salud, sedes, directorios médicos, cobertura en el exterior, programas especiales y servicios en línea para cuidar tu bienestar.','Pólizas y servicios de salud de SURA para cuidar tu bienestar y el de tu familia.','https://www.sura.co/seguros/personas/salud',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-vida-accidentes-personales','Seguro de Accidentes Personales',(SELECT id FROM ramo WHERE slug='personas-vida'),'personas','natural','Con el Seguro de Accidentes Personales SURA te respaldamos en caso de que sufras un accidente. Te indemnizamos a ti o a tus beneficiarios en caso de invalidez o fallecimiento como resultado de un accidente. Tambien puedes contratar coberturas adicionales como renta diaria por incapacidad y reembolso de gastos medicos en los que incurras a causa de un accidente y que tu EPS o seguro de salud no cubran.','Seguro que indemniza al asegurado o a sus beneficiarios en caso de invalidez, desmembracion o fallecimiento por accidente, con coberturas opcionales de renta diaria y gastos de curacion.','https://www.sura.co/seguros/personas/vida/accidentes/personales',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-vida-credito-protegido','Plan Crédito Protegido',(SELECT id FROM ramo WHERE slug='personas-vida'),'personas','natural','El Plan Crédito Protegido es un seguro de vida que respalda tu deuda con la entidad financiera en caso de fallecimiento o de una incapacidad total y permanente. A la hora de solicitar un crédito o préstamo, cualquier entidad financiera te exige un seguro de vida en caso de que no puedas cumplir con la deuda. Cubre el capital más los intereses corrientes y moratorios, y si después del pago queda parte del valor asegurado, este se entrega a ti o a tus beneficiarios.','Seguro de vida que paga tu crédito o préstamo en caso de fallecimiento o incapacidad total y permanente, devolviendo el excedente a ti o tus beneficiarios.','https://www.sura.co/seguros/personas/vida/credito/protegido',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-vida-educacion','Seguro de Educación',(SELECT id FROM ramo WHERE slug='personas-vida'),'personas','natural','Con el Seguro de Educación de SURA puedes estructurar un plan de pagos que te permita construir el capital necesario para cubrir los costos de tu educación o la de tus seres queridos en el futuro. Esta solución te ayuda a cubrir gastos de matrícula y manutención para estudios primarios, secundarios, no convencionales y universitarios, ya sean de pregrado o posgrado. También aplica para educación en el exterior, como viajes de intercambio. Está libre de cualquier obligación financiera: si dejas de pagarlo no se cancela, no adquieres una deuda, y te desembolsamos el capital que hayas acumulado en las fechas acordadas.','Seguro de vida-ahorro que acumula capital para pagar matrícula y manutención de estudios, libre de obligación financiera.','https://www.sura.co/seguros/personas/vida/educacion',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-vida-exequias','Seguro de Exequias SURA',(SELECT id FROM ramo WHERE slug='personas-vida'),'personas','natural','El Seguro de Exequias de SURA está diseñado para proporcionar un apoyo integral en caso de fallecimiento de un ser querido, para que la familia no tenga que asumir las grandes sumas de dinero que implica un proceso funerario. SURA entrega entre $3.000.000 y $7.000.000 de pesos para pagar todo el proceso exequial y, en caso de que sobre dinero, lo entrega a los beneficiarios, garantizando que familiares y amigos no tengan que preocuparse por los gastos funerarios.','Seguro de exequias que entrega entre $3.000.000 y $7.000.000 para cubrir gastos funerarios y entrega el excedente a los beneficiarios.','https://www.sura.co/seguros/personas/vida/exequias',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-vida-pension','Seguro de Pensión',(SELECT id FROM ramo WHERE slug='personas-vida'),'personas','natural','Con este seguro, adquieres una cultura de planeación financiera y al mismo tiempo aseguras los ingresos que, en unos años, complementarán tu pensión. Te garantiza un capital de respaldo para que tus seres queridos y tú disfruten de calidad de vida en el futuro. Tú defines por cuánto tiempo quieres pagar el Seguro de Pensión y la periodicidad más cómoda: una suma única o a cuotas mensuales de mínimo $100.000, o sus equivalentes trimestrales, semestrales o anuales. El ingreso mensual que recibirás en el futuro no pierde valor en el tiempo y el riesgo financiero lo asume SURA.','Seguro de ahorro y pensión que complementa tus ingresos futuros con un capital de respaldo y rentas mensuales que no pierden valor en el tiempo.','https://www.sura.co/seguros/personas/vida/pension',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-vida-seguro-de-vida','Seguro de Vida',(SELECT id FROM ramo WHERE slug='personas-vida'),'personas','natural','Garantizar y mantener tu independencia económica frente a cualquier imprevisto es importante para ti, al igual que disponer de un fondo de ahorro para hacer realidad tus sueños, así como los de tus seres queridos. Por ello, con nuestro Seguro de Vida Plan Vive, puedes estar tranquilo mientras proteges tus ingresos. Tienes la opción de contratar un fondo de ahorro para concretar tus proyectos a corto plazo o complementarlo con el Seguro de Pensión para asegurar tu calidad de vida en la etapa de retiro. De esta manera, te aseguras de disfrutar plenamente de la vida, alcanzando todas tus metas y compartiendo momentos especiales con tus seres queridos. Cualquier persona a partir de los 14 años puede adquirir su seguro de vida Plan Vive con las coberturas que mejor se adapten a su situación y estilo de vida.','Seguro de vida que protege tus ingresos y los de tus seres queridos, con opción de ahorro y coberturas ajustables a tu momento de vida.','https://www.sura.co/seguros/personas/vida/seguro/de/vida','https://www.segurossura.com.co/paginas/vida/inicio.aspx?utm_source=referral&utm_medium=segurossura&utm_term=cotizador-ss&utm_content=boton&utm_campaign=vida-segurossura',TRUE) ON CONFLICT(slug) DO NOTHING;
INSERT INTO producto(slug,nombre,ramo_id,linea,tipo_persona,descripcion,resumen,url,cotizador_url,es_digital) VALUES('personas-vida','Seguros de Vida SURA',(SELECT id FROM ramo WHERE slug='personas-vida'),'personas','natural','Sabemos que amas la vida, que disfrutas haciendo felices a tus seres queridos y regalándote instantes inolvidables. Sabemos que quieres seguir aprendiendo, explorando el mundo y viviendo experiencias únicas. En SURA queremos ser parte de cada uno de esos momentos con el respaldo que necesitas para aprovecharlos al máximo.','Portafolio de seguros de vida de SURA para acompañarte y proteger a tus seres queridos en cada momento.','https://www.sura.co/seguros/personas/vida',NULL,FALSE) ON CONFLICT(slug) DO NOTHING;
