INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='colectivos'),'juridica',NULL,NULL,'{}'::jsonb,'Solución dirigida a grandes empresas que buscan asegurar su patrimonio y el bienestar de sus empleados, así como a entidades aliadas (empresas de servicios públicos, cajas de compensación y entidades financieras).');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-agro-bovino-bufalino'),'ambas',NULL,NULL,'{}'::jsonb,'Ganaderos de todos los tamaños.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-agro-cosecha'),'ambas',NULL,NULL,'{}'::jsonb,'Agricultores de todos los tamaños.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-agro-planta'),'ambas',NULL,NULL,'{}'::jsonb,'Agricultores de todos los tamaños.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-colectivos-autos'),'juridica',NULL,NULL,'{"minimo_vehiculos":7}'::jsonb,'Sin importar el tamaño de tu empresa, podrán ser asegurados los vehículos de los empleados de tu empresa y sus familiares, según condiciones; siempre que se cumpla un mínimo de siete (7) carros para conformar la póliza colectiva. También aseguramos otros tipos de vehículos (utilitarios, livianos y pesados) que apoyen la operación de tu empresa, como motos, bicicletas, patinetas eléctricas y otros.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-colectivos-pension'),'juridica',NULL,NULL,'{}'::jsonb,'Dirigido a empresas que quieran ofrecer a sus empleados una alternativa para construir un capital que complemente su pensión. Aporte mínimo de cuotas mensuales de $100.000 o sus equivalentes trimestrales, semestrales o anuales.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-colectivos-vida-accidentes-personales'),'juridica',NULL,NULL,'{}'::jsonb,'A personas que hacen parte de un colectivo laboral y que, por la naturaleza de su trabajo, están expuestas a riesgos accidentales.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-construccion-equipo-electronico'),'ambas',NULL,NULL,'{"equipos_asegurables":"Equipos de cómputo, control, comunicaciones, sistematización y, en general, aquellos de esencia electrónica utilizados en tu negocio.","deberes_asegurado":["Mantener tus equipos en buen estado.","No someter tus equipos electrónicos a sobrecargas de forma habitual.","No utilizar tus bienes en labores para las que no son adecuados.","Proteger los equipos con red de puesta a tierra, supresores de picos y regulador de voltaje."]}'::jsonb,'Útil para empresas y profesionales que dependen de tecnología avanzada y equipos especializados en su operativa diaria. Puedes asegurar equipos de cómputo, control, comunicaciones, sistematización y, en general, aquellos de esencia electrónica utilizados en tu negocio.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-construccion-maquinaria-equipo-contratistas'),'ambas',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños y personas naturales que cuenten con maquinaria de los sectores construcción, agrícola, industrial, entre otros. Algunas de las máquinas y equipos que este seguro protege son: maquinaria amarilla (retroexcavadoras, buldóceres y vibrocompactadoras), maquinaria agrícola y forestal, equipo de levantamiento de cargas, y maquinaria instalada sobre chasis.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-construccion-montaje'),'ambas',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños y personas naturales que vayan a iniciar un montaje, ya sea de maquinaria de gran tamaño, plantas o estructuras metálicas de todo tipo.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-construccion-obras-civiles-terminadas'),'juridica',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños públicas o privadas, concesiones y asociaciones público-privadas que estén encargas de la operación de una obra de infraestructura.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-construccion-seguro-construccion'),'ambas',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños y personas naturales que vayan a iniciar un proyecto de construcción.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-corporativos-pymes-multirriesgo-copropiedades'),'juridica',NULL,NULL,'{"ley_675_2001":"Aplica a toda propiedad horizontal (perteneciente a dos o más propietarios), obligada a asegurar los bienes comunes."}'::jsonb,'Dirigido a copropiedades comerciales o industriales y sus áreas comunes; propiedades horizontales obligadas por la Ley 675 de 2001 a cubrir sus bienes comunes contra riesgos como incendios y terremotos.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-cumplimiento-arrendamiento'),'juridica',NULL,NULL,'{}'::jsonb,'Dirigido a empresas arrendadoras. El seguro está disponible de manera individual (un seguro por cada propiedad arrendada) y colectiva (incluida en un seguro colectivo que toman las agencias inmobiliarias para cubrir los riesgos de sus contratos de arrendamiento).');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-cumplimiento-caucion-judicial'),'ambas',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños y personas naturales que estén involucrados en un proceso jurídico o administrativo.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-cumplimiento-contratistas-proveedores'),'ambas',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños y personas naturales que firmen un contrato con tu empresa y deben garantizar su cumplimiento.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-cumplimiento-disposiciones-legales'),'ambas',NULL,NULL,'{}'::jsonb,'El tomador son las empresas de todos los tamaños y personas naturales. La entidad estatal será la asegurada.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-cumplimiento-entidades-estatales'),'ambas',NULL,NULL,'{}'::jsonb,'El tomador son las empresas de todos los tamaños y personas naturales que celebren contratos con entidades estatales para prestar un servicio, producir algo, construir una obra, entre otros. La entidad estatal será la asegurada.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-cumplimiento-grandes-beneficiarios'),'ambas',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños y personas naturales que firmen un contrato con tu empresa.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-cumplimiento-particulares'),'ambas',NULL,NULL,'{}'::jsonb,'El tomador son las empresas de todos los tamaños y personas naturales que sean contratados formalmente para prestar un servicio, producir algo, construir una obra, entre otros. El contratante será el asegurado.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-cumplimiento-servicios-publicos'),'ambas',NULL,NULL,'{}'::jsonb,'El tomador son las empresas de todos los tamaños y personas naturales que sean contratadas formalmente para prestar un servicio, producir algo, construir una obra, entre otros. La empresa de servicios públicos será la asegurada.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-energia-eficiencia-energetica'),'ambas',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños y personas naturales que hayan sido contratados para realizar un proyecto de eficiencia energética o generación de energía y deban garantizar su cumplimiento. Los proyectos asegurables incluyen: energía solar, iluminación, sistemas de refrigeración, cogeneración y otros equipos como motores, calderas y turbinas.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-politica-suscripcion-asg'),'juridica',NULL,NULL,'{"lineas_de_negocio":["Movilidad","Propiedad y patrimoniales","Riesgos logísticos y marítimos","Cumplimiento e ingeniería","Vida y salud"]}'::jsonb,'Esta política aplica a los procesos de suscripción de las siguientes líneas de negocio de Seguros SURA Colombia: Movilidad; Propiedad y patrimoniales; Riesgos logísticos y marítimos; Cumplimiento e ingeniería; Vida y salud. También es un insumo clave para el diseño de nuevas soluciones y servicios de gestión de riesgos.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-responsabilidad-civil-ambiental'),'juridica',NULL,NULL,'{}'::jsonb,'Empresas de todos los tamaños cuyas actividades económicas puedan generar una contaminación accidental, ya sea súbita o gradual, que afecte directamente su propio predio o el de terceros.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-responsabilidad-civil-clinicas-hospitales'),'juridica',NULL,NULL,'{}'::jsonb,'Clínicas y hospitales legalmente habilitados para prestar servicios de salud.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-responsabilidad-civil-danos-terceros'),'juridica',NULL,NULL,'{}'::jsonb,'Cualquier empresa que desee protegerse ante la responsabilidad civil y quiera preservar su patrimonio. La empresa debe ser apta luego de un análisis de riesgo realizado por SURA.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-responsabilidad-civil-drones'),'ambas',NULL,NULL,'{"cumplimiento_regulatorio":"Cumplir con la reglamentación requerida por parte de la Aeronáutica Civil","uso":"Uso de drones en el desarrollo de la actividad económica"}'::jsonb,'A empresas de todos los tamaños y a personas naturales que usen drones en el desarrollo de su actividad económica cumpliendo con la reglamentación requerida por parte de la Aeronáutica Civil, y que, durante su uso puedan causar daños a terceros.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-responsabilidad-civil-familiar'),'natural',NULL,NULL,'{"perfiles":["Familias con hijos","Personas con mascotas","Personas que vivan en predios arrendados"],"alcance_familiar":"Asegurado principal y su familia en primer grado de consanguinidad que residan en el mismo predio: cónyuge, compañero permanente, padres e hijos, así como las mascotas del grupo familiar (perros y gatos)."}'::jsonb,'A las personas y sus familias: familias con hijos, personas con mascotas y personas que vivan en predios arrendados. En este seguro se cubre al asegurado principal y su familia en primer grado de consanguinidad, que residan en el mismo predio: cónyuge, compañero permanente, padres e hijos, así como también las mascotas del grupo familiar (perros y gatos).');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-responsabilidad-civil-fraude-empleado'),'juridica',NULL,NULL,'{"sectores_incluidos":["sector real","industrial","servicios"],"sectores_excluidos":["establecimientos financieros","corresponsales bancarios","fondos de empleados","comisionistas de bolsa","empresas del sector de hidrocarburos","transportes de valores","entidades promotoras de salud (EPS)"]}'::jsonb,'Empresas de todos los tamaños del sector real, industrial y de servicios. Excepto establecimientos financieros, corresponsales bancarios, fondos de empleados, comisionistas de bolsa, empresas del sector de hidrocarburos, transportes de valores y entidades promotoras de salud (EPS).');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-responsabilidad-civil-parqueaderos'),'ambas',NULL,NULL,'{}'::jsonb,'A parqueaderos públicos y privados que estén cerrados, vigilados, regulados, con control de acceso y de seguridad.');
