INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-sura'),'juridica',NULL,NULL,'{"equipos_asegurables":"Equipos de cómputo, control, comunicaciones, sistematización y, en general, aquellos de esencia electrónica utilizados en tu negocio.","deberes_asegurado":["Mantener tus equipos en buen estado.","No someter tus equipos electrónicos a sobrecargas de forma habitual.","No utilizar tus bienes en labores para las que no son adecuados.","Proteger los equipos con red de puesta a tierra, supresores de picos y regulador de voltaje."]}'::jsonb,'Dirigido a empresas y profesionales que dependen de tecnología avanzada y equipos especializados en su operativa diaria. Se pueden asegurar equipos de cómputo, control, comunicaciones, sistematización y, en general, aquellos de esencia electrónica utilizados en el negocio.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-transporte-cadena-abastecimiento'),'juridica',NULL,NULL,'{}'::jsonb,'A empresa generadora de carga dedicada a la fabricación, distribución mayorista, minorista, exportación, importación, entre otros. Te acompañamos cuando: transportas mercancías (materia prima, producto en proceso, producto terminado) de un punto a otro a nivel nacional e internacional; quieres generar confianza con tus proveedores y clientes garantizando la protección de la mercancía en todo el trayecto.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-transporte-carga-proyectos'),'juridica',NULL,NULL,'{}'::jsonb,'A propietarios, inversionistas, financiadores y contratistas principales encargados de realizar la construcción de proyectos. Esta solución está orientada a grandes proyectos de ingeniería, como plantas de generación de energía, de tratamiento de aguas, refinerías, obras mineras, ferroviarias, industriales y similares.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='empresas-transporte-mercancias-automatico'),'juridica',NULL,NULL,'{}'::jsonb,'A empresas dedicadas a la producción, distribución, importación o exportación de bienes.');
