INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-hogar-arrendamiento-tradicional'),'ambas',NULL,NULL,'{"tomador":"Propietario","tipo_tomador":"Natural / Jurídica","afianzado":"Inquilino","asegurado_beneficiario":"Propietario","tipo_inmueble":"Residencial / Comercial","valor_maximo_canon_mensual":"Sin límite"}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-hogar-arrendamiento'),'ambas',NULL,NULL,'{"digital":{"valor_arriendo_max":"Hasta 5 millones de pesos mensuales","uso_inmueble":"Solo residencial","duracion_contrato":"3, 6 o 12 meses","tipo_persona":"Natural (propietario e inquilino)","codeudor":"Si el inquilino es apto para el seguro 100% digital no necesitará codeudor; de lo contrario será dirigido al plan individual por oficina.","requisitos":["Correo electrónico del inquilino.","Número de matrícula inmobiliaria."]},"tradicional":{"valor_arriendo_max":"Sin límite","uso_inmueble":"Residencial y Comercial","duracion_contrato":"Desde 1 mes en adelante","tipo_persona":"Natural y jurídica","codeudor":"Dependiendo del valor del canon podrás necesitar codeudor; existen planes en los que no se necesita, consúltalo con la oficina de tu ciudad.","requisitos":["Diligenciamiento de formularios por parte del inquilino.","Presentación de un codeudor.","Copia de la cédula de ciudadanía tanto del inquilino como del codeudor.","Documentos que demuestren solvencia económica.","Certificado de tradición y libertad reciente, no mayor a 30 días."]}}'::jsonb,'Producto dirigido a propietarios que arriendan inmuebles. La modalidad digital aplica a personas naturales (propietario e inquilino) con arriendos residenciales de hasta 5 millones mensuales; la modalidad tradicional aplica a personas naturales y jurídicas, uso residencial y comercial, sin límite de canon.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-hogar-hogar'),'natural',NULL,NULL,'{}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-hogar-mascotas'),'natural',NULL,NULL,'{"especies_asegurables":["perros","gatos"],"edad_mascota_min":"3 meses","edad_mascota_max":"9 años","nota_edad":"Para asegurar a tu mascota por primera vez, esta debe tener entre 3 meses y 9 años de edad. Fuera de este rango, no se aceptan nuevas pólizas.","deducible_gastos_veterinarios":"4 SMDLV"}'::jsonb,'Especies asegurables: perros y gatos. Para asegurar a tu mascota por primera vez, esta debe tener entre 3 meses y 9 años de edad. Fuera de este rango, no se aceptan nuevas pólizas para mascotas.');
