INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-movilidad-bicicletas-patinetas'),'natural',NULL,NULL,'{"bicicletas_aseguradas":["Tradicionales de pedal (ruta, montaña y urbana)","Plegables","Eléctricas","De gasolina"],"valor_minimo_bici":"$600.000 (seiscientos mil pesos)","valor_maximo_bici":"$30.000.000 (treinta millones de pesos)","exclusion":"No aseguramos bicicletas o motocicletas eléctricas que por norma legal requieran SOAT y matrícula ante los organismos de tránsito.","inspeccion":"Es posible que necesites realizar la inspección virtual. Para patinetas se evalúa cada caso para definir el valor asegurado y si requiere inspección."}'::jsonb,'Este producto está dirigido principalmente a las personas que utilizan su bicicleta o patineta para el desplazamiento habitual en la ciudad, o como un medio de diversión y ejercicio no profesional.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-movilidad-motos-digital'),'natural',NULL,NULL,'{}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-movilidad-motos'),'natural',NULL,NULL,'{"tipo_moto":"Moto de alto cilindraje (mayor que 250 cc) o de bajo cilindraje (igual o menor que 250 cc), incluye motos eléctricas"}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-movilidad-peritaje'),'natural',NULL,NULL,'{"requiere_seguro_sura":false,"vehiculos":["autos","motos"],"modalidad":"presencial en Centros de Servicios","ciudades":["Bogotá","Cali","Medellín","Pereira","Rionegro"]}'::jsonb,'Servicio dirigido a quienes venden o adquieren un vehículo usado (auto o moto). Para este servicio no es necesario tener el seguro SURA. Se atiende de forma presencial en los Centros de Servicios de Bogotá, Cali, Medellín, Pereira y Rionegro.');
