INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-responsabilidad-civil-profesionales-salud'),'natural',NULL,NULL,'{}'::jsonb,'Las personas que trabajen en el sector de la salud, como médicos, enfermeras, odontólogos, auxiliares y terapeutas, entre otros, que busquen proteger su patrimonio.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-como-cuidarte'),'natural',NULL,NULL,'{}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-enfermedades-graves'),'natural',0,59,'{"edad_ingreso":"Entre 14 y 59 años (la solicitud indica entre 0 y 59 años)","edad_permanencia":"Asegurado hasta los 70 años, con renovación automática","requisitos":["Completar la solicitud","Llenar y firmar la declaración de asegurabilidad","Adjuntar la información médica y financiera necesaria"],"criterios":"Debe cumplir con las políticas de suscripción y los criterios médicos establecidos por SURA"}'::jsonb,'El seguro está disponible para todas las personas que quieran tener respaldo económico en caso de ser diagnosticadas con una enfermedad grave cubierta, siempre y cuando cumplan con las políticas de suscripción y los criterios médicos establecidos por SURA. Para adquirir el seguro necesitas: completar la solicitud, tener entre 0 y 59 años, llenar y firmar la declaración de asegurabilidad y adjuntar la información médica y financiera necesaria.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-mascotas-digital'),'natural',NULL,NULL,'{"edad_ingreso_meses_min":4,"edad_ingreso_anos_max":7,"continuidad":"Al cumplir 8 años la mascota puede continuar asegurada sin límite de edad con ajuste de la prima por edad","especies":["perros","gatos"],"max_mascotas_por_poliza":5,"ciudades_cobertura":["Bogotá (la Sabana)","Medellín (Área Metropolitana y Rionegro)","Barranquilla","Cali","Manizales","Pereira"],"carencia_general_dias":15,"carencia_especializada_meses":3,"personas_juridicas":"No pueden ser tomadores de pólizas familiares de Salud para Mascotas"}'::jsonb,'Cualquier persona natural (no empresas) puede asegurar a su perro o gato, siempre que cumpla con las validaciones internas de SURA. Se pueden ingresar perros o gatos desde los 4 meses hasta los 7 años; al cumplir 8 años continúan asegurados sin límite de edad con ajuste de prima. Las personas jurídicas no pueden ser tomadores. En una misma póliza se pueden asegurar hasta 5 mascotas. Es un plan de salud en red cerrada con cobertura en Bogotá (la Sabana), Medellín (Área Metropolitana y Rionegro), Barranquilla, Cali, Manizales y Pereira.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-plan-salud-modular'),'natural',NULL,NULL,'{}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-poliza-clasica'),'natural',NULL,70,'{"residencia":"Residir en Colombia","edad":"Menor de 70 años al ingreso","eps":"Afiliación vigente a una EPS del Régimen Contributivo del Sistema de Seguridad Social en Salud","permanencia":"La permanencia se mantiene sin importar la edad, excepto en seguros colectivos donde hijos y hermanos solteros dependientes solo permanecen hasta el fin de la vigencia en la que cumplan 35 años","traslado_exterior":"El seguro termina automáticamente en caso de traslado permanente al exterior, salvo aceptación por escrito de exclusión de cobertura en el exterior","salud":"No sufrir ninguna enfermedad grave o de alto costo al momento de la adquisición"}'::jsonb,'Si resides en Colombia, tienes menos de 70 años y cuentas con afiliación vigente a una EPS del Régimen Contributivo del Sistema de Seguridad Social en Salud, puedes adquirir esta solución.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-poliza-evoluciona'),'natural',NULL,69,'{"residencia":"Colombia","edad_ingreso":"Menores de 70 años","afiliacion_eps":"Afiliación vigente a una EPS del Régimen Contributivo del Sistema de Seguridad Social en Salud","permanencia":"La permanencia se mantendrá sin importar su edad, excepto en los seguros colectivos, en los cuales los hijos y hermanos solteros dependientes del afiliado solo podrán permanecer hasta que termine la vigencia en la que cumplan 35 años.","traslado_exterior":"En caso de traslado al exterior, el seguro termina automáticamente, salvo aceptación por escrito de la exclusión de cobertura en el exterior propuesta por SURA."}'::jsonb,'Si resides en Colombia, tienes menos de 70 años y cuentas con afiliación vigente a una EPS del Régimen Contributivo del Sistema de Seguridad Social en Salud, puedes adquirir este plan.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-poliza-global'),'natural',NULL,63,'{"residencia":"Residencia en Colombia","edad_ingreso":"Menor de 63 anos al momento de la contratacion","permanencia":"Sin edad maxima para permanecer una vez ingresado (salvo seguros colectivos)","dependientes_colectivos":"Hijos y hermanos solteros dependientes pueden permanecer hasta el fin de la vigencia en que cumplen 35 anos","afiliacion_eps":"Estar afiliado vigente a una EPS del regimen contributivo de salud en Colombia","traslado_exterior":"El seguro termina automaticamente si el asegurado se traslada a vivir al exterior, salvo aceptacion por escrito de exclusion de cobertura internacional"}'::jsonb,'Para acceder a los beneficios del plan se debe: 1. Residir en Colombia. 2. Tener edad maxima de 63 anos para ser elegible. 3. Estar afiliado de forma vigente a traves de una EPS del regimen contributivo de salud en Colombia.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-poliza'),'natural',NULL,NULL,'{"afiliacion_eps":"El asegurado debe estar afiliado y mantenerse activo en una EPS del Régimen Contributivo (Ley 1438, artículos 37 y 41)."}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-renta-diaria'),'natural',NULL,59,'{"valor_asegurable_min":"$50.000 diarios","valor_asegurable_max":"$200.000 diarios","suma_grupo_familiar":"La suma elegida debe ser la misma para todo el grupo familiar","plan_segun_afiliacion":"Plan Renta Diaria POS si solo tiene afiliacion al POS; Plan Renta Diaria PAS si ya tiene medicina prepagada, seguro de salud o Plan Complementario de Salud"}'::jsonb,'Si tienes 59 anos o menos, este plan es para ti. Puedes asegurar entre $50.000 y $200.000 diarios, y la suma elegida debe ser la misma para todo el grupo familiar.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-salud-para-dos'),'natural',0,100,'{"edad_afiliado_principal":"El afiliado principal debe ser mayor de 18 anos.","perfiles":"Aplica para independientes, PYMES y regimenes especiales como magisterio y fuerzas armadas.","copagos":"Sin copagos.","personas_cubiertas":"Puede compartir las coberturas con una persona registrada como beneficiario."}'::jsonb,'No tiene limite de edad. Podran asegurarse personas entre los 0 y 100 anos. El afiliado principal debera ser mayor de 18 anos. Aplica para independientes, PYMES y regimenes especiales como magisterio y fuerzas armadas, sin copagos.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-salud-para-todos'),'natural',0,59,'{"afiliacion_eps":"Afiliados a EPS SURA regimen contributivo","edad_ingreso":"3 meses a 59 anos","ciudades_cobertura":["Bogota","Chia","Medellin","Rionegro","Cali","Manizales","Pereira","Armenia","Barranquilla","Bucaramanga","Marinilla","La Ceja","Palmira","Santa Marta"]}'::jsonb,'Dirigido a afiliados a EPS SURA del regimen contributivo, con edad de ingreso de 3 meses a 59 anos, en las ciudades con cobertura.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-viajes-digital'),'natural',NULL,NULL,'{}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud-viajes'),'natural',0,74,'{"seguro_internacional":"Disponible para clientes entre 0 y 74 años","seguro_nacional":"Sin ningún límite de edad","evaluacion_medica":"No se requiere evaluación médica ni declaración de asegurabilidad"}'::jsonb,'Las personas que quieren disfrutar al máximo un viaje nacional o internacional, terrestre o aéreo, solas o en compañía de sus seres queridos, con el respaldo de SURA. Las coberturas están disponibles para clientes que tengan entre 0 y 74 años en el caso de seguro internacional, y sin ningún límite de edad para el nacional. No se requiere evaluación médica ni declaración de asegurabilidad.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-salud'),'natural',NULL,NULL,'{}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-vida-accidentes-personales'),'natural',14,65,'{"politicas_suscripcion":"De acuerdo con las politicas de suscripcion de Seguros SURA y los criterios de evaluacion medica establecidos.","edad_terminacion":"El seguro se termina si cumples 75 anos."}'::jsonb,'El Seguro de Accidentes Personales esta disponible para todas las personas a partir de los 14 anos y hasta los 65 anos de edad, de acuerdo con las politicas de suscripcion de Seguros SURA y los criterios de evaluacion medica establecidos.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-vida-credito-protegido'),'natural',18,70,'{"edad_minima_ingreso":"18 años","edad_maxima_ingreso":"70 años","edad_maxima_permanencia_vida":"80 años","edad_maxima_permanencia_incapacidad":"75 años","edad_maxima_permanencia_auxilio_exequias":"80 años"}'::jsonb,'Edades de ingreso y permanencia: Vida (ingreso de 18 a 70 años, permanencia hasta 80 años); Incapacidad total y permanente por enfermedad o accidente (ingreso de 18 a 70 años, permanencia hasta 75 años); Auxilio de exequias (ingreso de 18 a 70 años, permanencia hasta 80 años). Si cumples la edad máxima de permanencia en cualquiera de las coberturas, sigues asegurado hasta que termine la vigencia actual de tu seguro.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-vida-educacion'),'natural',18,70,'{"evaluacion_medica_cobertura_principal":false,"declaracion_asegurabilidad_cobertura_principal":false,"requisitos_coberturas_opcionales":["Diligenciar la solicitud","Cumplir con la edad requerida de acuerdo con las políticas establecidas","Diligenciar y firmar la declaración de asegurabilidad","Adjuntar la información médica y financiera requerida"],"rango_edad_coberturas_opcionales":"18 a 70 años"}'::jsonb,'Todas las personas que desean construir un patrimonio que respalde el cumplimiento de sus metas educativas y las de sus seres queridos. El Seguro de Educación de SURA te da la libertad de elegir a los beneficiarios, es fácil de adquirir y no requiere evaluación médica o declaración de asegurabilidad. Las coberturas opcionales están disponibles para cualquier persona interesada que tenga entre 18 y 70 años de edad, según las políticas de suscripción de SURA y los criterios de evaluación médica establecidos.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-vida-exequias'),'natural',NULL,NULL,'{}'::jsonb,NULL);
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-vida-pension'),'natural',NULL,NULL,'{"asegurables":["titular","cónyuge","hijo","ser querido familiar o no familiar"],"max_asegurados":5,"evaluacion_medica":false,"declaracion_asegurabilidad":false,"libre_eleccion_beneficiarios":true}'::jsonb,'El Seguro de Pensión está disponible para todas las personas que desean construir un patrimonio: para ti, para tu cónyuge, para tu hijo o para un ser querido que puede ser o no tu familiar. Te damos la libertad de elegir los beneficiarios y no requieres evaluación médica o declaración de asegurabilidad para adquirir el producto. Puedes definir hasta 5 asegurados en caso de que alguno falte.');
INSERT INTO elegibilidad(producto_id,tipo_persona,edad_min,edad_max,condiciones,descripcion) VALUES((SELECT id FROM producto WHERE slug='personas-vida-seguro-de-vida'),'natural',14,NULL,'{}'::jsonb,'Cualquier persona a partir de los 14 años puede adquirir su seguro de vida Plan Vive con las coberturas que mejor se adapten a su situación y estilo de vida.');
